/*--------------------------------------------------------------------*/
/*                        DATABASE SETUP                              */
/*--------------------------------------------------------------------*/
DROP DATABASE IF EXISTS moviedb;

CREATE DATABASE IF NOT EXISTS moviedb CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;

SET default_storage_engine=InnoDB; 
USE moviedb; 

DROP TABLE IF EXISTS reviews; 
DROP TABLE IF EXISTS watchlist; 
DROP TABLE IF EXISTS movie_genres; 
DROP TABLE IF EXISTS users; 
DROP TABLE IF EXISTS movies; 
DROP TABLE IF EXISTS genres;

/*--------------------------------------------------------------------*/
/*                        TABLE DEFINITIONS                           */
/*--------------------------------------------------------------------*/

CREATE TABLE genres(
    genre_id            INT                 NOT NULL    AUTO_INCREMENT,
    genre_name          VARCHAR(50)         NOT NULL    UNIQUE,
    
    CONSTRAINT          genres_PK           PRIMARY KEY(genre_id),
    
    INDEX               idx_genre_name(genre_name)
);

CREATE TABLE movies(
    movie_id            INT                 NOT NULL    AUTO_INCREMENT,
    title               VARCHAR(255)        NOT NULL,
    release_year        YEAR,
    runtime             INT,                                -- in minutes
    director            VARCHAR(100),
    rated               VARCHAR(10),                        -- MPAA rating: G, PG, PG-13, R, etc.
    description         TEXT,
    imdb_rating         DECIMAL(3,1),                       -- e.g., 9.3
    imdb_votes          INT,
    poster_url          VARCHAR(500),
    
    CONSTRAINT          movies_PK           PRIMARY KEY(movie_id),
    
    INDEX               idx_title(title),
    INDEX               idx_year(release_year),
    INDEX               idx_director(director),
    INDEX               idx_rating(imdb_rating)
);

CREATE TABLE movie_genres(
    movie_id            INT                 NOT NULL,
    genre_id            INT                 NOT NULL,
    
    CONSTRAINT          movie_genres_PK     PRIMARY KEY(movie_id, genre_id),
    CONSTRAINT          movies_mg_FK        FOREIGN KEY(movie_id)
                        REFERENCES movies(movie_id)
                        ON UPDATE CASCADE
                        ON DELETE CASCADE,
    CONSTRAINT          genres_mg_FK        FOREIGN KEY(genre_id)
                        REFERENCES genres(genre_id)
                        ON UPDATE CASCADE
                        ON DELETE CASCADE,
    
    INDEX               idx_movie(movie_id),
    INDEX               idx_genre(genre_id)
);

CREATE TABLE users(
    user_id             INT                 NOT NULL    AUTO_INCREMENT,
    first_name          VARCHAR(50)         NOT NULL,
    last_name           VARCHAR(50)         NOT NULL,
    email               VARCHAR(100)        NOT NULL    UNIQUE,
    subscription_type   ENUM('free', 'basic', 'premium')    DEFAULT 'free',
    join_date           DATE                NOT NULL,
    
    CONSTRAINT          users_PK            PRIMARY KEY(user_id),
    
    INDEX               idx_email(email),
    INDEX               idx_subscription(subscription_type),
    INDEX               idx_name(last_name, first_name)
);

CREATE TABLE watchlist(
    watchlist_id        INT                 NOT NULL    AUTO_INCREMENT,
    user_id             INT                 NOT NULL,
    movie_id            INT                 NOT NULL,
    date_added          DATE                NOT NULL,
    watched             BOOLEAN             DEFAULT FALSE,
    
    CONSTRAINT          watchlist_PK        PRIMARY KEY(watchlist_id),
    CONSTRAINT          users_watchlist_FK  FOREIGN KEY(user_id)
                        REFERENCES users(user_id)
                        ON UPDATE CASCADE
                        ON DELETE CASCADE,
    CONSTRAINT          movies_watchlist_FK FOREIGN KEY(movie_id)
                        REFERENCES movies(movie_id)
                        ON UPDATE CASCADE
                        ON DELETE CASCADE,
    
    INDEX               idx_user(user_id),
    INDEX               idx_movie(movie_id),
    INDEX               idx_watched(watched),
    INDEX               idx_date(date_added)
);

CREATE TABLE reviews(
    review_id           INT                 NOT NULL    AUTO_INCREMENT,
    user_id             INT                 NOT NULL,
    movie_id            INT                 NOT NULL,
    rating              DECIMAL(2,1)        NOT NULL,   -- 1.0 to 5.0 stars
    review_text         TEXT,
    review_date         DATE                NOT NULL,
    
    CONSTRAINT          reviews_PK          PRIMARY KEY(review_id),
    CONSTRAINT          users_reviews_FK    FOREIGN KEY(user_id)
                        REFERENCES users(user_id)
                        ON UPDATE CASCADE
                        ON DELETE CASCADE,
    CONSTRAINT          movies_reviews_FK   FOREIGN KEY(movie_id)
                        REFERENCES movies(movie_id)
                        ON UPDATE CASCADE
                        ON DELETE CASCADE,
    CONSTRAINT          rating_range        CHECK(rating >= 1.0 AND rating <= 5.0),
    
    INDEX               idx_user(user_id),
    INDEX               idx_movie(movie_id),
    INDEX               idx_rating(rating),
    INDEX               idx_date(review_date)
);



