INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (1, 'Inception', '2010', 148, 'Christopher Nolan', 'PG-13', 'Cobb, a skilled thief who commits corporate espionage by infiltrating the subconscious of his targets is offered a chance to regain his old life as payment for a task considered to be impossible: "inception", the implantation of another person''s idea into a target''s subconscious.', '8.8', '2781889', 'https://m.media-amazon.com/images/M/MV5BMjAxMzY3NjcxNF5BMl5BanBnXkFtZTcwNTI5OTM0Mw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (2, 'The Dark Knight', '2008', 152, 'Christopher Nolan', 'PG-13', 'Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.', '9.1', '3135889', 'https://m.media-amazon.com/images/M/MV5BMTMxNTMwODM0NF5BMl5BanBnXkFtZTcwODAyMTk2Mw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (3, 'Avatar', '2009', 162, 'James Cameron', 'PG-13', 'In the 22nd century, a paraplegic Marine is dispatched to the moon Pandora on a unique mission, but becomes torn between following orders and protecting an alien civilization.', '7.9', '1486308', 'https://m.media-amazon.com/images/M/MV5BMDEzMmQwZjctZWU2My00MWNlLWE0NjItMDJlYTRlNGJiZjcyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (4, 'The Avengers', '2012', 143, 'Joss Whedon', 'PG-13', 'When an unexpected enemy emerges and threatens global safety and security, Nick Fury, director of the international peacekeeping agency known as S.H.I.E.L.D., finds himself in need of a team to pull the world back from the brink of disaster. Spanning the globe, a daring recruitment effort begins!', '8.0', '1547278', 'https://m.media-amazon.com/images/M/MV5BNGE0YTVjNzUtNzJjOS00NGNlLTgxMzctZTY4YTE1Y2Y1ZTU4XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (5, 'Deadpool', '2016', 108, 'Tim Miller', 'R', 'Deadpool tells the origin story of former Special Forces operative turned mercenary Wade Wilson, who after being subjected to a rogue experiment that leaves him with accelerated healing powers, adopts the alter ego Deadpool. Armed with his new abilities and a dark, twisted sense of humor, Deadpool hunts down the man who nearly destroyed his life.', '8.0', '1240356', 'https://m.media-amazon.com/images/M/MV5BNzY3ZWU5NGQtOTViNC00ZWVmLTliNjAtNzViNzlkZWQ4YzQ4XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (6, 'Interstellar', '2014', 169, 'Christopher Nolan', 'PG-13', 'Interstellar chronicles the adventures of a group of explorers who make use of a newly discovered wormhole to surpass the limitations on human space travel and conquer the vast distances involved in an interstellar voyage.', '8.7', '2472939', 'https://m.media-amazon.com/images/M/MV5BYzdjMDAxZGItMjI2My00ODA1LTlkNzItOWFjMDU5ZDJlYWY3XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (7, 'Django Unchained', '2012', 165, 'Quentin Tarantino', 'R', 'With the help of a German bounty hunter, a freed slave sets out to rescue his wife from a brutal Mississippi plantation owner.', '8.5', '1864939', 'https://m.media-amazon.com/images/M/MV5BMjIyNTQ5NjQ1OV5BMl5BanBnXkFtZTcwODg1MDU4OA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (8, 'Guardians of the Galaxy', '2014', 121, 'James Gunn', 'PG-13', 'Light years from Earth, 26 years after being abducted, Peter Quill finds himself the prime target of a manhunt after discovering an orb wanted by Ronan the Accuser.', '8.0', '1352030', 'https://m.media-amazon.com/images/M/MV5BM2ZmNjQ2MzAtNDlhNi00MmQyLWJhZDMtNmJiMjFlOWY4MzcxXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (9, 'The Hunger Games', '2012', 142, 'Gary Ross', 'PG-13', 'Every year in the ruins of what was once North America, the nation of Panem forces each of its twelve districts to send a teenage boy and girl to compete in the Hunger Games.  Part twisted entertainment, part government intimidation tactic, the Hunger Games are a nationally televised event in which “Tributes” must fight with one another until one survivor remains.  Pitted against highly-trained Tributes who have prepared for these Games their entire lives, Katniss is forced to rely upon her shar', '7.2', '1066839', 'https://m.media-amazon.com/images/M/MV5BMWI1OGM4YjQtNmIxNi00YmE2LWJkNTAtY2Q0YjU4NTI5NWQyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (10, 'Mad Max: Fury Road', '2015', 120, 'George Miller', 'R', 'An apocalyptic story set in the furthest reaches of our planet, in a stark desert landscape where humanity is broken, and most everyone is crazed fighting for the necessities of life. Within this world exist two rebels on the run who just might be able to restore order. There''s Max, a man of action and a man of few words, who seeks peace of mind following the loss of his wife and child in the aftermath of the chaos. And Furiosa, a woman of action and a woman who believes her path to survival may', '8.1', '1198396', 'https://m.media-amazon.com/images/M/MV5BZDRkODJhOTgtOTc1OC00NTgzLTk4NjItNDgxZDY4YjlmNDY2XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (11, 'Fight Club', '1999', 139, 'David Fincher', 'R', 'A ticking-time-bomb insomniac and a slippery soap salesman channel primal male aggression into a shocking new form of therapy. Their concept catches on, with underground "fight clubs" forming in every town, until an eccentric gets in the way and ignites an out-of-control spiral toward oblivion.', '8.8', '2567948', 'https://m.media-amazon.com/images/M/MV5BOTgyOGQ1NDItNGU3Ny00MjU3LTg2YWEtNmEyYjBiMjI1Y2M5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (12, 'The Dark Knight Rises', '2012', 164, 'Christopher Nolan', 'PG-13', 'Following the death of District Attorney Harvey Dent, Batman assumes responsibility for Dent''s crimes to protect the late attorney''s reputation and is subsequently hunted by the Gotham City Police Department. Eight years later, Batman encounters the mysterious Selina Kyle and the villainous Bane, a new terrorist leader who overwhelms Gotham''s finest. The Dark Knight resurfaces to protect a city that has branded him an enemy.', '8.4', '1974176', 'https://m.media-amazon.com/images/M/MV5BMTk4ODQzNDY3Ml5BMl5BanBnXkFtZTcwODA0NTM4Nw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (13, 'The Matrix', '1999', 136, 'Lana Wachowski, Lilly Wachowski', 'R', 'Set in the 22nd century, The Matrix tells the story of a computer hacker who joins a group of underground insurgents fighting the vast and powerful computers who now rule the earth.', '8.7', '2228203', 'https://m.media-amazon.com/images/M/MV5BN2NmN2VhMTQtMDNiOS00NDlhLTliMjgtODE2ZTY0ODQyNDRhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (14, 'Iron Man 3', '2013', 130, 'Shane Black', 'PG-13', 'When Tony Stark''s world is torn apart by a formidable terrorist called the Mandarin, he starts an odyssey of rebuilding and retribution.', '7.1', '957295', 'https://m.media-amazon.com/images/M/MV5BMjIzMzAzMjQyM15BMl5BanBnXkFtZTcwNzM2NjcyOQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (15, 'Iron Man', '2008', 126, 'Jon Favreau', 'PG-13', 'After being held captive in an Afghan cave, billionaire engineer Tony Stark creates a unique weaponized suit of armor to fight evil.', '7.9', '1213667', 'https://m.media-amazon.com/images/M/MV5BMTczNTI2ODUwOF5BMl5BanBnXkFtZTcwMTU0NTIzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (16, 'The Lord of the Rings: The Fellowship of the Ring', '2001', 178, 'Peter Jackson', 'PG-13', 'Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.', '8.9', '2181462', 'https://m.media-amazon.com/images/M/MV5BNzIxMDQ2YTctNDY4MC00ZTRhLTk4ODQtMTVlOWY4NTdiYmMwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (17, 'Jurassic World', '2015', 124, 'Colin Trevorrow', 'PG-13', 'Twenty-two years after the events of Jurassic Park, Isla Nublar now features a fully functioning dinosaur theme park, Jurassic World, as originally envisioned by John Hammond.', '6.9', '723175', 'https://m.media-amazon.com/images/M/MV5BNzBhNzlkM2UtZTQyOC00NjUyLTkzMmMtNDQ1YTM5N2NmMGE5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (18, 'Pulp Fiction', '1994', 154, 'Quentin Tarantino', 'R', 'A burger-loving hit man, his philosophical partner, a drug-addled gangster''s moll and a washed-up boxer converge in this sprawling, comedic crime caper. Their adventures unfurl in three stories that ingeniously trip back and forth in time.', '8.8', '2410498', 'https://m.media-amazon.com/images/M/MV5BYTViYTE3ZGQtNDBlMC00ZTAyLTkyODMtZGRiZDg0MjA2YThkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (19, 'The Hobbit: An Unexpected Journey', '2012', 169, 'Peter Jackson', 'PG-13', 'Bilbo Baggins, a hobbit enjoying his quiet life, is swept into an epic quest by Gandalf the Grey and thirteen dwarves who seek to reclaim their mountain home from Smaug, the dragon.', '7.8', '920968', 'https://m.media-amazon.com/images/M/MV5BMTcwNTE4MTUxMl5BMl5BanBnXkFtZTcwMDIyODM4OA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (20, 'The Shawshank Redemption', '1994', 142, 'Frank Darabont', 'R', 'Framed in the 1940s for the double murder of his wife and her lover, upstanding banker Andy Dufresne begins a new life at the Shawshank prison, where he puts his accounting skills to work for an amoral warden. During his long stretch in prison, Dufresne comes to be admired by the other inmates -- including an older prisoner named Red -- for his integrity and unquenchable sense of hope.', '9.3', '3152337', 'https://m.media-amazon.com/images/M/MV5BMDAyY2FhYjctNDc5OS00MDNlLThiMGUtY2UxYWVkNGY2ZjljXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (21, 'The Lord of the Rings: The Return of the King', '2003', 201, 'Peter Jackson', 'PG-13', 'Aragorn is revealed as the heir to the ancient kings as he, Gandalf and the other members of the broken fellowship struggle to save Gondor from Sauron''s forces. Meanwhile, Frodo and Sam bring the ring closer to the heart of Mordor, the dark lord''s realm.', '9.0', '2142025', 'https://m.media-amazon.com/images/M/MV5BMTZkMjBjNWMtZGI5OC00MGU0LTk4ZTItODg2NWM3NTVmNWQ4XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (22, 'Forrest Gump', '1994', 142, 'Robert Zemeckis', 'PG-13', 'A man with a low IQ has accomplished great things in his life and been present during significant historic events - in each case, far exceeding what anyone imagined he could do. Yet, despite all the things he has attained, his one true love eludes him. ''Forrest Gump'' is the story of a man who rose above his challenges, and who proved that determination, courage, and love are more important than ability.', '8.8', '2467350', 'https://m.media-amazon.com/images/M/MV5BNDYwNzVjMTItZmU5YS00YjQ5LTljYjgtMjY2NDVmYWMyNWFmXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (23, 'Skyfall', '2012', 143, 'Sam Mendes', 'PG-13', 'When Bond''s latest assignment goes gravely wrong and agents around the world are exposed, MI6 is attacked forcing M to relocate the agency. These events cause her authority and position to be challenged by Gareth Mallory, the new Chairman of the Intelligence and Security Committee. With MI6 now compromised from both inside and out, M is left with one ally she can trust: Bond. 007 takes to the shadows - aided only by field agent, Eve - following a trail to the mysterious Silva, whose lethal and h', '7.8', '768360', 'https://m.media-amazon.com/images/M/MV5BNjAzMWNkODUtM2FlMi00NzgyLWJhMGUtMWEyNDYyZGFiN2RlXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (24, 'Titanic', '1997', 194, 'James Cameron', 'PG-13', '84 years later, a 101-year-old woman named Rose DeWitt Bukater tells the story to her granddaughter Lizzy Calvert, Brock Lovett, Lewis Bodine, Bobby Buell and Anatoly Mikailavich on the Keldysh about her life set in April 10th 1912, on a ship called Titanic when young Rose boards the departing ship with the upper-class passengers and her mother, Ruth DeWitt Bukater, and her fiancé, Caledon Hockley. Meanwhile, a drifter and artist named Jack Dawson and his best friend Fabrizio De Rossi win third-', '8.0', '1378313', 'https://m.media-amazon.com/images/M/MV5BYzYyN2FiZmUtYWYzMy00MzViLWJkZTMtOGY1ZjgzNWMwN2YxXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (25, 'The Lord of the Rings: The Two Towers', '2002', 179, 'Peter Jackson', 'PG-13', 'Frodo and Sam are trekking to Mordor to destroy the One Ring of Power while Gimli, Legolas and Aragorn search for the orc-captured Merry and Pippin. All along, nefarious wizard Saruman awaits the Fellowship members at the Orthanc Tower in Isengard.', '8.8', '1939468', 'https://m.media-amazon.com/images/M/MV5BMGQxMDdiOWUtYjc1Ni00YzM1LWE2NjMtZTg3Y2JkMjEzMTJjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (26, 'Batman Begins', '2005', 140, 'Christopher Nolan', 'PG-13', 'Driven by tragedy, billionaire Bruce Wayne dedicates his life to uncovering and defeating the corruption that plagues his home, Gotham City.  Unable to work within the system, he instead creates a new identity, a symbol of fear for the criminal underworld - The Batman.', '8.2', '1700042', 'https://m.media-amazon.com/images/M/MV5BMzA2NDQzZDEtNDU5Ni00YTlkLTg2OWEtYmQwM2Y1YTBjMjFjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (27, 'The Martian', '2015', 144, 'Ridley Scott', 'PG-13', 'During a manned mission to Mars, Astronaut Mark Watney is presumed dead after a fierce storm and left behind by his crew. But Watney has survived and finds himself stranded and alone on the hostile planet. With only meager supplies, he must draw upon his ingenuity, wit and spirit to subsist and find a way to signal to Earth that he is alive.', '8.0', '999128', 'https://m.media-amazon.com/images/M/MV5BMTc2MTQ3MDA1Nl5BMl5BanBnXkFtZTgwODA3OTI4NjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (28, 'Captain America: Civil War', '2016', 147, 'Anthony Russo, Joe Russo', 'PG-13', 'Following the events of Age of Ultron, the collective governments of the world pass an act designed to regulate all superhuman activity. This polarizes opinion amongst the Avengers, causing two factions to side with Iron Man or Captain America, which causes an epic battle between former allies.', '7.8', '917200', 'https://m.media-amazon.com/images/M/MV5BMjQ0MTgyNjAxMV5BMl5BanBnXkFtZTgwNjUzMDkyODE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (29, 'Captain America: The First Avenger', '2011', 124, 'Joe Johnston', 'PG-13', 'Predominantly set during World War II, Steve Rogers is a sickly man from Brooklyn who''s transformed into super-soldier Captain America to aid in the war effort. Rogers must stop the Red Skull – Adolf Hitler''s ruthless head of weaponry, and the leader of an organization that intends to use a mysterious device of untold powers for world domination.', '6.9', '958774', 'https://m.media-amazon.com/images/M/MV5BNzUyM2YyY2MtNzNlMS00MWU5LTgxNjAtNzZlNmI2NjU2NDZlXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (30, 'Harry Potter and the Philosopher''s Stone', '2001', 152.0, NULL, NULL, 'Harry Potter has lived under the stairs at his aunt and uncle''s house his whole life. But on his 11th birthday, he learns he''s a powerful wizard -- with a place waiting for him at the Hogwarts School of Witchcraft and Wizardry. As he learns to harness his newfound powers with the help of the school''s kindly headmaster, Harry uncovers the truth about his parents'' deaths -- and about the villain who''s to blame.', NULL, NULL, NULL);
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (31, 'Pirates of the Caribbean: The Curse of the Black Pearl', '2003', 143, 'Gore Verbinski', 'PG-13', 'Jack Sparrow, a freewheeling 17th-century pirate who roams the Caribbean Sea, butts heads with a rival pirate bent on pillaging the village of Port Royal. When the governor''s daughter is kidnapped, Sparrow decides to help the girl''s love save her. But their seafaring mission is hardly simple.', '8.1', '1312218', 'https://m.media-amazon.com/images/M/MV5BNDhlMzEyNzItMTA5Mi00YWRhLThlNTktYTQyMTA0MDIyNDEyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (32, 'Up', '2009', 96, 'Pete Docter, Bob Peterson', 'PG', 'Carl Fredricksen spent his entire life dreaming of exploring the globe and experiencing life to its fullest. But at age 78, life seems to have passed him by, until a twist of fate (and a persistent 8-year old Wilderness Explorer named Russell) gives him a new lease on life.', '8.3', '1204006', 'https://m.media-amazon.com/images/M/MV5BNmI1ZTc5MWMtMDYyOS00ZDc2LTkzOTAtNjQ4NWIxNjYyNDgzXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (33, 'Iron Man 2', '2010', 124, 'Jon Favreau', 'PG-13', 'With the world now aware of his dual life as the armored superhero Iron Man, billionaire inventor Tony Stark faces pressure from the government, the press and the public to share his technology with the military. Unwilling to let go of his invention, Stark, with Pepper Potts and James ''Rhodey'' Rhodes at his side, must forge new alliances – and confront powerful enemies.', '6.9', '924662', 'https://m.media-amazon.com/images/M/MV5BYWYyOGQzOGYtMGQ1My00ZWYxLTgzZjktZWYzN2IwYjkxYzM0XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (34, 'Avengers: Age of Ultron', '2015', 141, 'Joss Whedon', 'PG-13', 'When Tony Stark tries to jumpstart a dormant peacekeeping program, things go awry and Earth’s Mightiest Heroes are put to the ultimate test as the fate of the planet hangs in the balance. As the villainous Ultron emerges, it is up to The Avengers to stop him from enacting his terrible plans, and soon uneasy alliances and unexpected action pave the way for an epic and unique global adventure.', '7.3', '984646', 'https://m.media-amazon.com/images/M/MV5BODBhYTg1NGQtNGVmNS00ZTdiLThjYTYtZDFkNzRiNTZmNDZjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (35, 'Star Wars', '1977', 121, 'George Lucas', 'PG', 'Princess Leia is captured and held hostage by the evil Imperial forces in their effort to take over the galactic Empire. Venturesome Luke Skywalker and dashing captain Han Solo team together with the loveable robot duo R2-D2 and C-3PO to rescue the beautiful princess and restore peace and justice in the Empire.', '8.6', '1555851', 'https://m.media-amazon.com/images/M/MV5BOGUwMDk0Y2MtNjBlNi00NmRiLTk2MWYtMGMyMDlhYmI4ZDBjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (36, 'The Amazing Spider-Man', '2012', 136, 'Marc Webb', 'PG-13', 'Peter Parker is an outcast high schooler abandoned by his parents as a boy, leaving him to be raised by his Uncle Ben and Aunt May. Like most teenagers, Peter is trying to figure out who he is and how he got to be the person he is today. As Peter discovers a mysterious briefcase that belonged to his father, he begins a quest to understand his parents'' disappearance – leading him directly to Oscorp and the lab of Dr. Curt Connors, his father''s former partner. As Spider-Man is set on a collision c', '6.9', '755835', 'https://m.media-amazon.com/images/M/MV5BMjMyOTM4MDMxNV5BMl5BanBnXkFtZTcwNjIyNzExOA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (37, 'The Wolf of Wall Street', '2013', 180, 'Martin Scorsese', 'R', 'A New York stockbroker refuses to cooperate in a large securities fraud case involving corruption on Wall Street, corporate banking world and mob infiltration. Based on Jordan Belfort''s autobiography.', '8.2', '1759293', 'https://m.media-amazon.com/images/M/MV5BMjIxMjgxNTk0MF5BMl5BanBnXkFtZTgwNjIyOTg2MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (38, 'Inside Out', '2015', 95, 'Pete Docter, Ronnie Del Carmen', 'PG', 'Growing up can be a bumpy road, and it''s no exception for Riley, who is uprooted from her Midwest life when her father starts a new job in San Francisco. Like all of us, Riley is guided by her emotions - Joy, Fear, Anger, Disgust and Sadness. The emotions live in Headquarters, the control center inside Riley''s mind, where they help advise her through everyday life. As Riley and her emotions struggle to adjust to a new life in San Francisco, turmoil ensues in Headquarters. Although Joy, Riley''s m', '8.1', '905131', 'https://m.media-amazon.com/images/M/MV5BOTgxMDQwMDk0OF5BMl5BanBnXkFtZTgwNjU5OTg2NDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (39, 'Thor', '2011', 115, 'Kenneth Branagh', 'PG-13', 'Against his father Odin''s will, The Mighty Thor - a powerful but arrogant warrior god - recklessly reignites an ancient war. Thor is cast down to Earth and forced to live among humans as punishment. Once here, Thor learns what it takes to be a true hero when the most dangerous villain of his world sends the darkest forces of Asgard to invade Earth.', '7.0', '958893', 'https://m.media-amazon.com/images/M/MV5BNjRhNGZjZjEtYTQzYS00OWUxLThjNGEtMTIwMTE2ZDFlZTZkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (40, 'The Hunger Games: Catching Fire', '2013', 146, 'Francis Lawrence', 'PG-13', 'Katniss Everdeen has returned home safe after winning the 74th Annual Hunger Games along with fellow tribute Peeta Mellark. Winning means that they must turn around and leave their family and close friends, embarking on a "Victor''s Tour" of the districts. Along the way Katniss senses that a rebellion is simmering, but the Capitol is still very much in control as President Snow prepares the 75th Annual Hunger Games (The Quarter Quell) - a competition that could change Panem forever.', '7.5', '768630', 'https://m.media-amazon.com/images/M/MV5BMTAyMjQ3OTAxMzNeQTJeQWpwZ15BbWU4MDU0NzA1MzAx._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (41, 'Despicable Me', '2010', 95, 'Pierre Coffin, Chris Renaud', 'PG', 'Villainous Gru lives up to his reputation as a despicable, deplorable and downright unlikable guy when he hatches a plan to steal the moon from the sky. But he has a tough time staying on task after three orphans land in his care.', '7.6', '624710', 'https://m.media-amazon.com/images/M/MV5BMTY3NjY0MTQ0Nl5BMl5BanBnXkFtZTcwMzQ2MTc0Mw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (42, 'Inglourious Basterds', '2009', 153, 'Quentin Tarantino', 'R', 'In Nazi-occupied France during World War II, a group of Jewish-American soldiers known as "The Basterds" are chosen specifically to spread fear throughout the Third Reich by scalping and brutally killing Nazis. The Basterds, lead by Lt. Aldo Raine soon cross paths with a French-Jewish teenage girl who runs a movie theater in Paris which is targeted by the soldiers.', '8.4', '1762277', 'https://m.media-amazon.com/images/M/MV5BODZhMWJlNjYtNDExNC00MTIzLTllM2ItOGQ2NGVjNDQ3MzkzXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (43, 'The Revenant', '2015', 156, 'Alejandro G. Iñárritu', 'R', 'In the 1820s, a frontiersman, Hugh Glass, sets out on a path of vengeance against those who left him for dead after a bear mauling.', '8.0', '941249', 'https://m.media-amazon.com/images/M/MV5BYTgwNmQzZDctMjNmOS00OTExLTkwM2UtNzJmOTJhODFjOTdlXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (44, 'Man of Steel', '2013', 143, 'Zack Snyder', 'PG-13', 'A young boy learns that he has extraordinary powers and is not of this earth. As a young man, he journeys to discover where he came from and what he was sent here to do. But the hero in him must emerge if he is to save the world from annihilation and become the symbol of hope for all mankind.', '7.1', '861907', 'https://m.media-amazon.com/images/M/MV5BMTk5ODk1NDkxMF5BMl5BanBnXkFtZTcwNTA5OTY0OQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (45, 'Shutter Island', '2010', 138, 'Martin Scorsese', 'R', 'World War II soldier-turned-U.S. Marshal Teddy Daniels investigates the disappearance of a patient from a hospital for the criminally insane, but his efforts are compromised by his troubling visions and also by a mysterious doctor.', '8.2', '1607676', 'https://m.media-amazon.com/images/M/MV5BN2FjNWExYzEtY2YzOC00YjNlLTllMTQtNmIwM2Q1YzBhOWM1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (46, 'WALL·E', '2008', 98, 'Andrew Stanton', 'G', 'WALL·E is the last robot left on an Earth that has been overrun with garbage and all humans have fled to outer space. For 700 years he has continued to try and clean up the mess, but has developed some rather interesting human-like qualities. When a ship arrives with a sleek new type of robot, WALL·E thinks he''s finally found a friend and stows away on the ship when it leaves.', '8.4', '1306354', 'https://m.media-amazon.com/images/M/MV5BMjExMTg5OTU0NF5BMl5BanBnXkFtZTcwMjMxMzMzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (47, 'The Hangover', '2009', 100, 'Todd Phillips', 'R', 'When three friends finally come to after a raucous night of bachelor-party revelry, they find a baby in the closet and a tiger in the bathroom. But they can''t seem to locate their best friend, Doug – who''s supposed to be tying the knot. Launching a frantic search for Doug, the trio perseveres through a nasty hangover to try to make it to the church on time.', '7.7', '910547', 'https://m.media-amazon.com/images/M/MV5BNDI2MzBhNzgtOWYyOS00NDM2LWE0OGYtOGQ0M2FjMTI2NTllXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (48, 'Big Hero 6', '2014', 102, 'Don Hall, Chris Williams', 'PG', 'The special bond that develops between plus-sized inflatable robot Baymax, and prodigy Hiro Hamada, who team up with a group of friends to form a band of high-tech heroes.', '7.8', '548572', 'https://m.media-amazon.com/images/M/MV5BYjQ3YzUyOGQtNjdlYS00YmRhLWIyOWYtMGQ3YjkwMjJiYzRjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (49, 'Finding Nemo', '2003', 100, 'Andrew Stanton, Lee Unkrich', 'G', 'Nemo, an adventurous young clownfish, is unexpectedly taken from his Great Barrier Reef home to a dentist''s office aquarium. It''s up to his worrisome father Marlin and a friendly but forgetful fish Dory to bring Nemo home -- meeting vegetarian sharks, surfer dude turtles, hypnotic jellyfish, hungry seagulls, and more along the way.', '8.2', '1196544', 'https://m.media-amazon.com/images/M/MV5BMTc5NjExNTA5OV5BMl5BanBnXkFtZTYwMTQ0ODY2._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (50, 'Back to the Future', '1985', 116, 'Robert Zemeckis', 'PG', 'Eighties teenager Marty McFly is accidentally sent back in time to 1955, inadvertently disrupting his parents'' first meeting and attracting his mother''s romantic interest. Marty must repair the damage to history by rekindling his parents'' romance and - with the help of his eccentric inventor friend Doc Brown - return to 1985.', '8.5', '1436086', 'https://m.media-amazon.com/images/M/MV5BZmM3ZjE0NzctNjBiOC00MDZmLTgzMTUtNGVlOWFlOTNiZDJiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (51, 'X-Men: Days of Future Past', '2014', 132, 'Bryan Singer', 'PG-13', 'The ultimate X-Men ensemble fights a war for the survival of the species across two time periods as they join forces with their younger selves in an epic battle that must change the past – to save our future.', '7.9', '784622', 'https://m.media-amazon.com/images/M/MV5BNzNiYWE4NjMtMTU4OS00NmM4LWE4ZjAtYmE5OTA5NjkzODExXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (52, 'Monsters, Inc.', '2001', 92, 'Pete Docter, David Silverman, Lee Unkrich', 'G', 'James Sullivan and Mike Wazowski are monsters, they earn their living scaring children and are the best in the business... even though they''re more afraid of the children than they are of them. When a child accidentally enters their world, James and Mike suddenly find that kids are not to be afraid of and they uncover a conspiracy that could threaten all children across the world.', '8.1', '1065059', 'https://m.media-amazon.com/images/M/MV5BMTY1NTI0ODUyOF5BMl5BanBnXkFtZTgwNTEyNjQ0MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (53, 'The Godfather', '1972', 175, 'Francis Ford Coppola', 'R', 'Spanning the years 1945 to 1955, a chronicle of the fictional Italian-American Corleone crime family. When organized crime family patriarch, Vito Corleone barely survives an attempt on his life, his youngest son, Michael steps in to take care of the would-be killers, launching a campaign of bloody revenge.', '9.2', '2205717', 'https://m.media-amazon.com/images/M/MV5BNGEwYjgwOGQtYjg5ZS00Njc1LTk2ZGEtM2QwZWQ2NjdhZTE5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (54, 'Ant-Man', '2015', 117, 'Peyton Reed', 'PG-13', 'Armed with the astonishing ability to shrink in scale but increase in strength, master thief Scott Lang must embrace his inner-hero and help his mentor, Doctor Hank Pym, protect the secret behind his spectacular Ant-Man suit from a new generation of towering threats. Against seemingly insurmountable obstacles, Pym and Lang must plan and pull off a heist that will save the world.', '7.2', '769979', 'https://m.media-amazon.com/images/M/MV5BMjM2NTQ5Mzc2M15BMl5BanBnXkFtZTgwNTcxMDI2NTE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (55, 'The Empire Strikes Back', '1980', 124, 'Irvin Kershner', 'PG', 'The epic saga continues as Luke Skywalker, in hopes of defeating the evil Galactic Empire, learns the ways of the Jedi from aging master Yoda. But Darth Vader is more determined than ever to capture Luke. Meanwhile, rebel leader Princess Leia, cocky Han Solo, Chewbacca, and droids C-3PO and R2-D2 are thrown into various stages of capture, betrayal and despair.', '8.7', '1490112', 'https://m.media-amazon.com/images/M/MV5BMTkxNGFlNDktZmJkNC00MDdhLTg0MTEtZjZiYWI3MGE5NWIwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (56, 'Harry Potter and the Prisoner of Azkaban', '2004', 142, 'Alfonso Cuarón', 'PG', 'Harry, Ron and Hermione return to Hogwarts for another magic-filled year. Harry comes face to face with danger yet again, this time in the form of escaped convict, Sirius Black – and turns to sympathetic Professor Lupin for help.', '7.9', '758003', 'https://m.media-amazon.com/images/M/MV5BMTY4NTIwODg0N15BMl5BanBnXkFtZTcwOTc0MjEzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (57, 'Gone Girl', '2014', 149, 'David Fincher', 'R', 'With his wife''s disappearance having become the focus of an intense media circus, a man sees the spotlight turned on him when it''s suspected that he may not be innocent.', '8.1', '1158661', 'https://m.media-amazon.com/images/M/MV5BMTk0MDQ3MzAzOV5BMl5BanBnXkFtZTgwNzU1NzE3MjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (58, 'Harry Potter and the Chamber of Secrets', '2002', 161, 'Chris Columbus', 'PG', 'Ignoring threats to his life, Harry returns to Hogwarts to investigate – aided by Ron and Hermione – a mysterious series of attacks.', '7.5', '759564', 'https://m.media-amazon.com/images/M/MV5BNGJhM2M2MWYtZjIzMC00MDZmLThkY2EtOWViMDhhYjRhMzk4XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (59, 'Life of Pi', '2012', 127, 'Ang Lee', 'PG', 'The story of an Indian boy named Pi, a zookeeper''s son who finds himself in the company of a hyena, zebra, orangutan, and a Bengal tiger after a shipwreck sets them adrift in the Pacific Ocean.', '7.9', '697056', 'https://m.media-amazon.com/images/M/MV5BNTg2OTY2ODg5OF5BMl5BanBnXkFtZTcwODM5MTYxOA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (60, 'Sherlock Holmes', '2009', 128, 'Guy Ritchie', 'PG-13', 'Eccentric consulting detective, Sherlock Holmes and Doctor John Watson battle to bring down a new nemesis and unravel a deadly plot that could destroy England.', '7.5', '702387', 'https://m.media-amazon.com/images/M/MV5BMTg0NjEwNjUxM15BMl5BanBnXkFtZTcwMzk0MjQ5Mg@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (61, 'Se7en', '1995', 127, 'David Fincher', 'R', 'Two homicide detectives are on a desperate hunt for a serial killer whose crimes are based on the "seven deadly sins" in this dark and haunting film that takes viewers from the tortured remains of one victim to the next. The seasoned Det. Sommerset researches each sin in an effort to get inside the killer''s mind, while his novice partner, Mills, scoffs at his efforts to unravel the case.', '8.6', '1995504', 'https://m.media-amazon.com/images/M/MV5BY2IzNzMxZjctZjUxZi00YzAxLTk3ZjMtODFjODdhMDU5NDM1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (62, 'Captain America: The Winter Soldier', '2014', 136, 'Anthony Russo, Joe Russo', 'PG-13', 'After the cataclysmic events in New York with The Avengers, Steve Rogers, aka Captain America is living quietly in Washington, D.C. and trying to adjust to the modern world. But when a S.H.I.E.L.D. colleague comes under attack, Steve becomes embroiled in a web of intrigue that threatens to put the world at risk. Joining forces with the Black Widow, Captain America struggles to expose the ever-widening conspiracy while fighting off professional assassins sent to silence him at every turn. When th', '7.7', '957842', 'https://m.media-amazon.com/images/M/MV5BNWY1NjFmNDItZDhmOC00NjI1LWE0ZDItMTM0MjBjZThiOTQ2XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (63, 'Gravity', '2013', 91, 'Alfonso Cuarón', 'PG-13', 'Dr. Ryan Stone, a brilliant medical engineer on her first Shuttle mission, with veteran astronaut Matt Kowalsky in command of his last flight before retiring. But on a seemingly routine spacewalk, disaster strikes. The Shuttle is destroyed, leaving Stone and Kowalsky completely alone-tethered to nothing but each other and spiraling out into the blackness of space. The deafening silence tells them they have lost any link to Earth and any chance for rescue. As fear turns to panic, every gulp of ai', '7.7', '895643', 'https://m.media-amazon.com/images/M/MV5BNjE5MzYwMzYxMF5BMl5BanBnXkFtZTcwOTk4MTk0OQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (64, 'The Imitation Game', '2014', 114, 'Morten Tyldum', 'PG-13', 'Based on the real life story of legendary cryptanalyst Alan Turing, the film portrays the nail-biting race against time by Turing and his brilliant team of code-breakers at Britain''s top-secret Government Code and Cypher School at Bletchley Park, during the darkest days of World War II.', '8.0', '872710', 'https://m.media-amazon.com/images/M/MV5BNjI3NjY1Mjg3MV5BMl5BanBnXkFtZTgwMzk5MDQ3MjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (65, 'Harry Potter and the Goblet of Fire', '2005', 157, 'Mike Newell', 'PG-13', 'Harry starts his fourth year at Hogwarts, competes in the treacherous Triwizard Tournament and faces the evil Lord Voldemort. Ron and Hermione help Harry manage the pressure – but Voldemort lurks, awaiting his chance to destroy Harry and all that he stands for.', '7.7', '746138', 'https://m.media-amazon.com/images/M/MV5BMTIzNzUzOTk2NV5BMl5BanBnXkFtZTYwNTI4MDg2._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (66, 'The Hunger Games: Mockingjay - Part 1', '2014', 123, 'Francis Lawrence', 'PG-13', 'Katniss Everdeen reluctantly becomes the symbol of a mass rebellion against the autocratic Capitol.', '6.6', '541925', 'https://m.media-amazon.com/images/M/MV5BMTcxNDI2NDAzNl5BMl5BanBnXkFtZTgwODM3MTc2MjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (67, 'World War Z', '2013', 116, 'Marc Forster', 'PG-13', 'Life for former United Nations investigator Gerry Lane and his family seems content. Suddenly, the world is plagued by a mysterious infection turning whole human populations into rampaging mindless zombies. After barely escaping the chaos, Lane is persuaded to go on a mission to investigate this disease. What follows is a perilous trek around the world where Lane must brave horrific dangers and long odds to find answers before human civilization falls.', '7.0', '773594', 'https://m.media-amazon.com/images/M/MV5BODg3ZTM2YWQtZDE5Ny00NGNiLTkzYjgtYWVlYjNkOTg5NDI1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (68, 'Harry Potter and the Order of the Phoenix', '2007', 138, 'David Yates', 'PG-13', 'Returning for his fifth year of study at Hogwarts, Harry is stunned to find that his warnings about the return of Lord Voldemort have been ignored. Left with no choice, Harry takes matters into his own hands, training a small group of students – dubbed ''Dumbledore''s Army'' – to defend themselves against the dark arts.', '7.5', '693356', 'https://m.media-amazon.com/images/M/MV5BYWJmM2M1YzItMjY1Ni00YzRmLTg5YWYtNDFmNTJjNzQ0ODkyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (69, 'Now You See Me', '2013', 115, 'Louis Leterrier', 'PG-13', 'An FBI agent and an Interpol detective track a team of illusionists who pull off bank heists during their performances and reward their audiences with the money.', '7.2', '765172', 'https://m.media-amazon.com/images/M/MV5BMTY0NDY3MDMxN15BMl5BanBnXkFtZTcwOTM5NzMzOQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (70, 'Gladiator', '2000', 155, 'Ridley Scott', 'R', 'In the year 180, the death of emperor Marcus Aurelius throws the Roman Empire into chaos. Maximus is one of the Roman army''s most capable and trusted generals and a key advisor to the emperor. As Marcus'' devious son Commodus ascends to the throne, Maximus is set to be executed. He escapes, but is captured by slave traders. Renamed Spaniard and forced to become a gladiator, Maximus must battle to the death with other men for the amusement of paying audiences. His battle skills serve him well, and', '8.5', '1831468', 'https://m.media-amazon.com/images/M/MV5BYWQ4YmNjYjEtOWE1Zi00Y2U4LWI4NTAtMTU0MjkxNWQ1ZmJiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (71, 'The Lion King', '1994', 88, 'Roger Allers, Rob Minkoff', 'G', 'A young lion cub named Simba can''t wait to be king. But his uncle craves the title for himself and will stop at nothing to get it.', '8.5', '1248136', 'https://m.media-amazon.com/images/M/MV5BZGRiZDZhZjItM2M3ZC00Y2IyLTk3Y2MtMWY5YjliNDFkZTJlXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (72, 'The Maze Runner', '2014', 113, 'Wes Ball', 'PG-13', 'Set in a post-apocalyptic world, young Thomas is deposited in a community of boys after his memory is erased, soon learning they''re all trapped in a maze that will require him to join forces with fellow "runners" for a shot at escape.', '6.8', '557043', 'https://m.media-amazon.com/images/M/MV5BMjUyNTA3MTAyM15BMl5BanBnXkFtZTgwOTEyMTkyMjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (73, 'Frozen', '2013', 102, 'Chris Buck, Jennifer Lee', 'PG', 'Young princess Anna of Arendelle dreams about finding true love at her sister Elsa’s coronation. Fate takes her on a dangerous journey in an attempt to end the eternal winter that has fallen over the kingdom. She''s accompanied by ice delivery man Kristoff, his reindeer Sven, and snowman Olaf. On an adventure where she will find out what friendship, courage, family, and true love really means.', '7.4', '708011', 'https://m.media-amazon.com/images/M/MV5BMTQ1MjQwMTE5OF5BMl5BanBnXkFtZTgwNjk3MTcyMDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (74, 'Harry Potter and the Half-Blood Prince', '2009', 153, 'David Yates', 'PG', 'As Harry begins his sixth year at Hogwarts, he discovers an old book marked as ''Property of the Half-Blood Prince'', and begins to learn more about Lord Voldemort''s dark past.', '7.6', '653701', 'https://m.media-amazon.com/images/M/MV5BNzU3NDg4NTAyNV5BMl5BanBnXkFtZTcwOTg2ODg1Mg@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (75, 'Toy Story', '1995', 81, 'John Lasseter', 'G', 'Led by Woody, Andy''s toys live happily in his room until Andy''s birthday brings Buzz Lightyear onto the scene. Afraid of losing his place in Andy''s heart, Woody plots against Buzz. But when circumstances separate Buzz and Woody from their owner, the duo eventually learns to put aside their differences.', '8.3', '1163069', 'https://m.media-amazon.com/images/M/MV5BZTA3OWVjOWItNjE1NS00NzZiLWE1MjgtZDZhMWI1ZTlkNzYwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (76, 'Spider-Man', '2002', 121, 'Sam Raimi', 'PG-13', 'After being bitten by a genetically altered spider, nerdy high school student Peter Parker is endowed with amazing powers.', '7.4', '958249', 'https://m.media-amazon.com/images/M/MV5BZWM0OWVmNTEtNWVkOS00MzgyLTkyMzgtMmE2ZTZiNjY4MmFiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (77, 'Pirates of the Caribbean: Dead Man''s Chest', '2006', 151, 'Gore Verbinski', 'PG-13', 'Captain Jack Sparrow works his way out of a blood debt with the ghostly Davey Jones, he also attempts to avoid eternal damnation.', '7.4', '819899', 'https://m.media-amazon.com/images/M/MV5BMTcwODc1MTMxM15BMl5BanBnXkFtZTYwMDg1NzY3._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (78, 'X-Men: First Class', '2011', 131, 'Matthew Vaughn', 'PG-13', 'Before Charles Xavier and Erik Lensherr took the names Professor X and Magneto, they were two young men discovering their powers for the first time. Before they were arch-enemies, they were closest of friends, working together with other mutants (some familiar, some new), to stop the greatest threat the world has ever known.', '7.7', '759828', 'https://m.media-amazon.com/images/M/MV5BMTg5OTMxNzk4Nl5BMl5BanBnXkFtZTcwOTk1MjAwNQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (79, 'The Incredibles', '2004', 115, 'Brad Bird', 'PG', 'Bob Parr has given up his superhero days to log in time as an insurance adjuster and raise his three children with his formerly heroic wife in suburbia. But when he receives a mysterious assignment, it''s time to get back into costume.', '8.0', '891503', 'https://m.media-amazon.com/images/M/MV5BMTY5OTU0OTc2NV5BMl5BanBnXkFtZTcwMzU4MDcyMQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (80, 'Saving Private Ryan', '1998', 169, 'Steven Spielberg', 'R', 'As U.S. troops storm the beaches of Normandy, three brothers lie dead on the battlefield, with a fourth trapped behind enemy lines. Ranger captain John Miller and seven men are tasked with penetrating German-held territory and bringing the boy home.', '8.6', '1624514', 'https://m.media-amazon.com/images/M/MV5BZGZhZGQ1ZWUtZTZjYS00MDJhLWFkYjctN2ZlYjE5NWYwZDM2XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (81, '300', '2006', 117, 'Zack Snyder', 'R', 'Based on Frank Miller''s graphic novel, "300" is very loosely based the 480 B.C. Battle of Thermopylae, where the King of Sparta led his army against the advancing Persians; the battle is said to have inspired all of Greece to band together against the Persians, and helped usher in the world''s first democracy.', '7.6', '904962', 'https://m.media-amazon.com/images/M/MV5BMjc4OTc0ODgwNV5BMl5BanBnXkFtZTcwNjM1ODE0MQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (82, 'Kill Bill: Vol. 1', '2003', 111, 'Quentin Tarantino', 'R', 'An assassin is shot at the altar by her ruthless employer, Bill and other members of their assassination circle – but ''The Bride'' lives to plot her vengeance. Setting out for some payback, she makes a death list and hunts down those who wronged her, saving Bill for last.', '8.2', '1295392', 'https://m.media-amazon.com/images/M/MV5BZmMyYzJlZmYtY2I3NC00NjAyLTkyZWItZjdjZDI1YTYyYTEwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (83, 'Edge of Tomorrow', '2014', 113, 'Doug Liman', 'PG-13', 'Major Bill Cage is an officer who has never seen a day of combat when he is unceremoniously demoted and dropped into combat. Cage is killed within minutes, managing to take an alpha alien down with him. He awakens back at the beginning of the same day and is forced to fight and die again... and again - as physical contact with the alien has thrown him into a time loop.', '7.9', '796841', 'https://m.media-amazon.com/images/M/MV5BMTc5OTk4MTM3M15BMl5BanBnXkFtZTgwODcxNjg3MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (84, 'Jurassic Park', '1993', 127, 'Steven Spielberg', 'PG-13', 'A wealthy entrepreneur secretly creates a theme park featuring living dinosaurs drawn from prehistoric DNA. Before opening day, he invites a team of experts and his two eager grandchildren to experience the park and help calm anxious investors. However, the park is anything but amusing as the security systems go off-line and the dinosaurs escape.', '8.2', '1167043', 'https://m.media-amazon.com/images/M/MV5BMjM2MDgxMDg0Nl5BMl5BanBnXkFtZTgwNTM2OTM5NDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (85, 'I Am Legend', '2007', 101, 'Francis Lawrence', 'PG-13', 'Robert Neville is a scientist who was unable to stop the spread of the terrible virus that was incurable and man-made. Immune, Neville is now the last human survivor in what is left of New York City and perhaps the world. For three years, Neville has faithfully sent out daily radio messages, desperate to find any other survivors who might be out there. But he is not alone.', '7.2', '870487', 'https://m.media-amazon.com/images/M/MV5BMGE1OWZkZmItNmVhMC00YzAxLTgxOTctNjg3NWExM2RmOWJkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (86, 'Pacific Rim', '2013', 131, 'Guillermo del Toro', 'PG-13', 'When legions of monstrous creatures, known as Kaiju, started rising from the sea, a war began that would take millions of lives and consume humanity''s resources for years on end. To combat the giant Kaiju, a special type of weapon was devised: massive robots, called Jaegers, which are controlled simultaneously by two pilots whose minds are locked in a neural bridge. But even the Jaegers are proving nearly defenseless in the face of the relentless Kaiju. On the verge of defeat, the forces defendi', '6.9', '555685', 'https://m.media-amazon.com/images/M/MV5BMTY3MTI5NjQ4Nl5BMl5BanBnXkFtZTcwOTU1OTU0OQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (87, 'The Hobbit: The Battle of the Five Armies', '2014', 144, 'Peter Jackson', 'R', 'Immediately after the events of The Desolation of Smaug, Bilbo and the dwarves try to defend Erebor''s mountain of treasure from others who claim it: the men of the ruined Laketown and the elves of Mirkwood. Meanwhile an army of Orcs led by Azog the Defiler is marching on Erebor, fueled by the rise of the dark lord Sauron. Dwarves, elves and men must unite, and the hope for Middle-Earth falls into Bilbo''s hands.', '7.4', '613512', 'https://m.media-amazon.com/images/M/MV5BMTYzNDE3OTQ3MF5BMl5BanBnXkFtZTgwODczMTg4MjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (88, 'Thor: The Dark World', '2013', 112, 'Alan Taylor', 'PG-13', 'Thor fights to restore order across the cosmos… but an ancient race led by the vengeful Malekith returns to plunge the universe back into darkness. Faced with an enemy that even Odin and Asgard cannot withstand, Thor must embark on his most perilous and personal journey yet, one that will reunite him with Jane Foster and force him to sacrifice everything to save us all.', '6.7', '771012', 'https://m.media-amazon.com/images/M/MV5BMTQyNzAwOTUxOF5BMl5BanBnXkFtZTcwMTE0OTc5OQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (89, 'Silver Linings Playbook', '2012', 122, 'David O. Russell', 'R', 'After spending eight months in a mental institution, a former teacher moves back in with his parents and tries to reconcile with his ex-wife.', '7.7', '770744', 'https://m.media-amazon.com/images/M/MV5BMTM2MTI5NzA3MF5BMl5BanBnXkFtZTcwODExNTc0OA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (90, 'Ex Machina', '2015', 29, NULL, NULL, 'Caleb, a 26 year old coder at the world''s largest internet company, wins a competition to spend a week at a private mountain retreat belonging to Nathan, the reclusive CEO of the company. But when Caleb arrives at the remote location he finds that he will have to participate in a strange and fascinating experiment in which he must interact with the world''s first true artificial intelligence, housed in the body of a beautiful robot girl.', '7.1', '33', NULL);
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (91, 'Looper', '2012', 119, 'Rian Johnson', 'R', 'In the futuristic action thriller Looper, time travel will be invented but it will be illegal and only available on the black market. When the mob wants to get rid of someone, they will send their target 30 years into the past where a looper, a hired gun, like Joe is waiting to mop up. Joe is getting rich and life is good until the day the mob decides to close the loop, sending back Joe''s future self for assassination.', '7.4', '624435', 'https://m.media-amazon.com/images/M/MV5BMTg5NTA3NTg4NF5BMl5BanBnXkFtZTcwNTA0NDYzOA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (92, 'Return of the Jedi', '1983', 131, 'Richard Marquand', 'PG', 'As Rebel leaders map their strategy for an all-out attack on the Emperor''s newer, bigger Death Star. Han Solo remains frozen in the cavernous desert fortress of Jabba the Hutt, the most loathsome outlaw in the universe, who is also keeping Princess Leia as a slave girl. Now a master of the Force, Luke Skywalker rescues his friends, but he cannot become a true Jedi Knight until he wages his own crucial battle against Darth Vader, who has sworn to win Luke over to the dark side of the Force.', '8.3', '1200333', 'https://m.media-amazon.com/images/M/MV5BNWEwOTI0MmUtMGNmNy00ODViLTlkZDQtZTg1YmQ3MDgyNTUzXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (93, 'Divergent', '2014', 139, 'Neil Burger', 'PG-13', 'In a world divided into factions based on personality types, Tris learns that she''s been classified as Divergent and won''t fit in. When she discovers a plot to destroy Divergents, Tris and the mysterious Four must find out what makes Divergents dangerous before it''s too late.', '6.6', '514284', 'https://m.media-amazon.com/images/M/MV5BMTYxMzYwODE4OV5BMl5BanBnXkFtZTgwNDE5MzE2MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (94, 'Kick-Ass', '2010', 117, 'Matthew Vaughn', 'R', 'Dave Lizewski is an unnoticed high school student and comic book fan who one day decides to become a super-hero, even though he has no powers, training or meaningful reason to do so.', '7.6', '618719', 'https://m.media-amazon.com/images/M/MV5BMTMzNzEzMDYxM15BMl5BanBnXkFtZTcwMTc0NTMxMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (95, 'Brave', '2012', 93, 'Mark Andrews, Brenda Chapman, Steve Purcell', 'PG', 'Brave is set in the mystical Scottish Highlands, where Mérida is the princess of a kingdom ruled by King Fergus and Queen Elinor. An unruly daughter and an accomplished archer, Mérida one day defies a sacred custom of the land and inadvertently brings turmoil to the kingdom. In an attempt to set things right, Mérida seeks out an eccentric old Wise Woman and is granted an ill-fated wish. Also figuring into Mérida’s quest — and serving as comic relief — are the kingdom’s three lords: the enormous ', '7.1', '475578', 'https://m.media-amazon.com/images/M/MV5BMzgwODk3ODA1NF5BMl5BanBnXkFtZTcwNjU3NjQ0Nw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (96, 'Despicable Me 2', '2013', 98, 'Pierre Coffin, Chris Renaud', 'PG', 'Gru is recruited by the Anti-Villain League to help deal with a powerful new super criminal.', '7.3', '455292', 'https://m.media-amazon.com/images/M/MV5BMTQxNzY1MjI5NF5BMl5BanBnXkFtZTcwNTI0MDY1OQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (97, 'Toy Story 3', '2010', 103, 'Lee Unkrich', 'G', 'Woody, Buzz, and the rest of Andy''s toys haven''t been played with in years. With Andy about to go to college, the gang find themselves accidentally left at a nefarious day care center. The toys must band together to escape and return home to Andy.', '8.3', '961588', 'https://m.media-amazon.com/images/M/MV5BMTgxOTY4Mjc0MF5BMl5BanBnXkFtZTcwNTA4MDQyMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (98, 'Wreck-It Ralph', '2012', 101, 'Rich Moore', 'PG', 'Wreck-It Ralph is the 9-foot-tall, 643-pound villain of an arcade video game named Fix-It Felix Jr., in which the game''s titular hero fixes buildings that Ralph destroys. Wanting to prove he can be a good guy and not just a villain, Ralph escapes his game and lands in Hero''s Duty, a first-person shooter where he helps the game''s hero battle against alien invaders. He later enters Sugar Rush, a kart racing game set on tracks made of candies, cookies and other sweets. There, Ralph meets Vanellope ', '7.7', '494419', 'https://m.media-amazon.com/images/M/MV5BNzMxNTExOTkyMF5BMl5BanBnXkFtZTcwMzEyNDc0OA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (99, 'The Truman Show', '1998', 103, 'Peter Weir', 'PG', 'Truman Burbank is the star of "The Truman Show", a 24-hour-a-day "reality" TV show that broadcasts every aspect of his life -- live and in color -- without his knowledge. His entire life has been an unending soap opera for consumption by the rest of the world. And everyone he knows -- including his wife and his best friend -- is really an actor, paid to be part of his life.', '8.2', '1339282', 'https://m.media-amazon.com/images/M/MV5BNzA3ZjZlNzYtMTdjMy00NjMzLTk5ZGYtMTkyYzNiOGM1YmM3XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (100, 'Birdman', '2014', 13, 'Guy Bolongaro', NULL, 'A fading actor best known for his portrayal of a popular superhero attempts to mount a comeback by appearing in a Broadway play. As opening night approaches, his attempts to become more altruistic, rebuild his career, and reconnect with friends and family prove more difficult than expected.', '5.1', '174', NULL);
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (101, 'The Hobbit: The Desolation of Smaug', '2013', 161, 'Peter Jackson', 'PG-13', 'The Dwarves, Bilbo and Gandalf have successfully escaped the Misty Mountains, and Bilbo has gained the One Ring. They all continue their journey to get their gold back from the Dragon, Smaug.', '7.8', '745112', 'https://m.media-amazon.com/images/M/MV5BMzU0NDY0NDEzNV5BMl5BanBnXkFtZTgwOTIxNDU1MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (102, 'The Grand Budapest Hotel', '2014', 99, 'Wes Anderson', 'R', 'The Grand Budapest Hotel tells of a legendary concierge at a famous European hotel between the wars and his friendship with a young employee who becomes his trusted protégé. The story involves the theft and recovery of a priceless Renaissance painting, the battle for an enormous family fortune and the slow and then sudden upheavals that transformed Europe during the first half of the 20th century.', '8.1', '956421', 'https://m.media-amazon.com/images/M/MV5BMzM5NjUxOTEyMl5BMl5BanBnXkFtZTgwNjEyMDM0MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (103, 'Star Trek', '2009', 127, 'J.J. Abrams', 'PG-13', 'The fate of the galaxy rests in the hands of bitter rivals. One, James Kirk, is a delinquent, thrill-seeking Iowa farm boy. The other, Spock, a Vulcan, was raised in a logic-based society that rejects all emotion. As fiery instinct clashes with calm reason, their unlikely but powerful partnership is the only thing capable of leading their crew through unimaginable danger, boldly going where no one has gone before. The human adventure has begun again.', '7.9', '636122', 'https://m.media-amazon.com/images/M/MV5BMjE5NDQ5OTE4Ml5BMl5BanBnXkFtZTcwOTE3NDIzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (104, 'Pirates of the Caribbean: At World''s End', '2007', 169, 'Gore Verbinski', 'PG-13', 'Captain Barbossa, long believed to be dead, has come back to life and is headed to the edge of the Earth with Will Turner and Elizabeth Swann. But nothing is quite as it seems.', '7.1', '739059', 'https://m.media-amazon.com/images/M/MV5BMjIyNjkxNzEyMl5BMl5BanBnXkFtZTYwMjc3MDE3._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (105, 'Maleficent', '2014', 97, 'Robert Stromberg', 'PG', 'The untold story of Disney''s most iconic villain from the 1959 classic ''Sleeping Beauty''. A beautiful, pure-hearted young woman, Maleficent has an idyllic life growing up in a peaceable forest kingdom, until one day when an invading army threatens the harmony of the land.  Maleficent rises to be the land''s fiercest protector, but she ultimately suffers a ruthless betrayal – an act that begins to turn her heart into stone. Bent on revenge, Maleficent faces an epic battle with the invading King''s ', '6.9', '420347', 'https://m.media-amazon.com/images/M/MV5BMjAwMzAzMzExOF5BMl5BanBnXkFtZTgwOTcwMDA5MTE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (106, 'Alien', '1979', 117, 'Ridley Scott', 'R', 'During its return to the earth, commercial spaceship Nostromo intercepts a distress signal from a distant planet. When a three-member team of the crew discovers a chamber containing thousands of eggs on the planet, a creature inside one of the eggs attacks an explorer. The entire crew is unaware of the impending nightmare set to descend upon them when the alien parasite planted inside its unfortunate host is birthed.', '8.5', '1055492', 'https://m.media-amazon.com/images/M/MV5BN2NhMDk2MmEtZDQzOC00MmY5LThhYzAtMDdjZGFjOGZjMjdjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (107, 'American Sniper', '2014', 133, 'Clint Eastwood', 'R', 'U.S. Navy SEAL Chris Kyle takes his sole mission—protect his comrades—to heart and becomes one of the most lethal snipers in American history. His pinpoint accuracy not only saves countless lives but also makes him a prime target of insurgents. Despite grave danger and his struggle to be a good husband and father to his family back in the States, Kyle serves four tours of duty in Iraq. However, when he finally returns home, he finds that he cannot leave the war behind.', '7.3', '565594', 'https://m.media-amazon.com/images/M/MV5BMTkxNzI3ODI4Nl5BMl5BanBnXkFtZTgwMjkwMjY4MjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (108, 'The Silence of the Lambs', '1991', 118, 'Jonathan Demme', 'R', 'FBI trainee, Clarice Starling ventures into a maximum-security asylum to pick the diseased brain of Hannibal Lecter, a psychiatrist turned homicidal cannibal. Starling needs clues to help her capture a serial killer. but her Faustian relationship with Lecter soon leads to his escape, and now two deranged killers are on the loose.', '8.6', '1690179', 'https://m.media-amazon.com/images/M/MV5BNDdhOGJhYzctYzYwZC00YmI2LWI0MjctYjg4ODdlMDExYjBlXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (109, 'V for Vendetta', '2006', 30, 'Josh Oreck', NULL, 'In a world in which Great Britain has become a fascist state, a masked vigilante known only as ''V'' conducts guerrilla warfare against the oppressive British government. When ''V'' rescues a young woman from the secret police, he finds in her an ally with whom he can continue his fight to free the people of Britain.', '7.6', '420', 'https://m.media-amazon.com/images/M/MV5BMDI2MzUwNDQtMDg5ZC00MWQ2LWE1NGItYzRkNTI0ZjAwZjJjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (110, 'Black Swan', '2010', 108, 'Darren Aronofsky', 'R', 'A ballet dancer wins the lead in "Swan Lake" and is perfect for the role of the delicate White Swan - Princess Odette - but slowly loses her mind as she becomes more and more like Odile, the Black Swan.', '8.0', '882921', 'https://m.media-amazon.com/images/M/MV5BNzY2NzI4OTE5MF5BMl5BanBnXkFtZTcwMjMyNDY4Mw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (111, 'Star Trek Into Darkness', '2013', 132, 'J.J. Abrams', 'PG-13', 'When the crew of the Enterprise is called back home, they find an unstoppable force of terror from within their own organization has detonated the fleet and everything it stands for, leaving our world in a state of crisis.  With a personal score to settle, Captain Kirk leads a manhunt to a war-zone world to capture a one man weapon of mass destruction. As our heroes are propelled into an epic chess game of life and death, love will be challenged, friendships will be torn apart, and sacrifices mu', '7.7', '509207', 'https://m.media-amazon.com/images/M/MV5BMTk2NzczOTgxNF5BMl5BanBnXkFtZTcwODQ5ODczOQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (112, 'Men in Black', '1997', 98, 'Barry Sonnenfeld', 'PG-13', 'Men in Black follows the exploits of agents Kay and Jay, members of a top-secret organization established to monitor and police alien activity on Earth. The two Men in Black find themselves in the middle of the deadly plot by an intergalactic terrorist who has arrived on Earth to assassinate two ambassadors from opposing galaxies. In order to prevent worlds from colliding, the MiB must track down the terrorist and prevent the destruction of Earth. It''s just another typical day for the Men in Bla', '7.3', '658335', 'https://m.media-amazon.com/images/M/MV5BZmQ0YTdhYzEtMjIxZC00MGFiLTlmNjktZmFlOWE2M2QxOTRhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (113, 'Dawn of the Planet of the Apes', '2014', 130, 'Matt Reeves', 'PG-13', 'A group of scientists in San Francisco struggle to stay alive in the aftermath of a plague that is wiping out humanity, while Caesar tries to maintain dominance over his community of intelligent apes.', '7.6', '508717', 'https://m.media-amazon.com/images/M/MV5BNWNjYzQ4ZGItZTg1My00NTM2LTg1NDUtYThjOTQwMTYyNjU1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (114, 'The Prestige', '2006', 130, 'Christopher Nolan', 'PG-13', 'A mysterious story of two magicians whose intense rivalry leads them on a life-long battle for supremacy -- full of obsession, deceit and jealousy with dangerous and deadly consequences.', '8.5', '1573561', 'https://m.media-amazon.com/images/M/MV5BMTM3MzQ5MjQ5OF5BMl5BanBnXkFtZTcwMTQ3NzMzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (115, 'Ratatouille', '2007', 111, 'Brad Bird, Jan Pinkava', 'G', 'A rat named Remy dreams of becoming a great French chef despite his family''s wishes and the obvious problem of being a rat in a decidedly rodent-phobic profession. When fate places Remy in the sewers of Paris, he finds himself ideally situated beneath a restaurant made famous by his culinary hero, Auguste Gusteau. Despite the apparent dangers of being an unlikely - and certainly unwanted - visitor in the kitchen of a fine French restaurant, Remy''s passion for cooking soon sets into motion a hila', '8.1', '922086', 'https://m.media-amazon.com/images/M/MV5BMTMzODU0NTkxMF5BMl5BanBnXkFtZTcwMjQ4MzMzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (116, 'Taken', '2008', 90, 'Pierre Morel', 'PG-13', 'While vacationing with a friend in Paris, an American girl is kidnapped by a gang of human traffickers intent on selling her into forced prostitution. Working against the clock, her ex-spy father must pull out all the stops to save her. But with his best years possibly behind him, the job may be more than he can handle.', '7.7', '666648', 'https://m.media-amazon.com/images/M/MV5BYTAxNTY2NjMtYjk5Yy00Nzg4LTkyMmItYmMzMDM2OWQ1ZGQ3XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (117, 'Rise of the Planet of the Apes', '2011', 105, 'Rupert Wyatt', 'PG-13', 'Scientist Will Rodman is determined to find a cure for Alzheimer''s, the disease which has slowly consumed his father. Will feels certain he is close to a breakthrough and tests his latest serum on apes, noticing dramatic increases in intelligence and brain activity in the primate subjects – especially Caesar, his pet chimpanzee.', '7.6', '600908', 'https://m.media-amazon.com/images/M/MV5BMjllODU1NDItODU1Ni00N2Y2LTg4Y2ItOTJjMTczZDliN2FhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (118, 'The Departed', '2006', 151, 'Martin Scorsese', 'R', 'To take down South Boston''s Irish Mafia, the police send in one of their own to infiltrate the underworld, not realizing the syndicate has done likewise. While an undercover cop curries favor with the mob kingpin, a career criminal rises through the police ranks. But both sides soon discover there''s a mole among them.', '8.5', '1538133', 'https://m.media-amazon.com/images/M/MV5BMTI1MTY2OTIxNV5BMl5BanBnXkFtZTYwNjQ4NjY3._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (119, 'Schindler''s List', '1993', 195, 'Steven Spielberg', 'R', 'The true story of how businessman Oskar Schindler saved over a thousand Jewish lives from the Nazis while they worked as slaves in his factory during World War II.', '9.0', '1573985', 'https://m.media-amazon.com/images/M/MV5BNjM1ZDQxYWUtMzQyZS00MTE1LWJmZGYtNGUyNTdlYjM3ZmVmXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (120, 'Spider-Man 2', '2004', 127, 'Sam Raimi', 'PG-13', 'Peter Parker is going through a major identity crisis. Burned out from being Spider-Man, he decides to shelve his superhero alter ego, which leaves the city suffering in the wake of carnage left by the evil Doc Ock. In the meantime, Parker still can''t act on his feelings for Mary Jane Watson, a girl he''s loved since childhood.', '7.5', '773982', 'https://m.media-amazon.com/images/M/MV5BNGQ0YTQyYTgtNWI2YS00NTE2LWJmNDItNTFlMTUwNmFlZTM0XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (121, 'The Hateful Eight', '2015', 168, 'Quentin Tarantino', 'R', 'Bounty hunters seek shelter from a raging blizzard and get caught up in a plot of betrayal and deception.', '7.8', '712947', 'https://m.media-amazon.com/images/M/MV5BMjA1MTc1NTg5NV5BMl5BanBnXkFtZTgwOTM2MDEzNzE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (122, 'Whiplash', '2014', 106, 'Damien Chazelle', 'R', 'Under the direction of a ruthless instructor, a talented young drummer begins to pursue perfection at any cost, even his humanity.', '8.5', '1134459', 'https://m.media-amazon.com/images/M/MV5BMDFjOWFkYzktYzhhMC00NmYyLTkwY2EtYjViMDhmNzg0OGFkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (123, 'How to Train Your Dragon', '2010', 98, 'Dean DeBlois, Chris Sanders', 'PG', 'As the son of a Viking leader on the cusp of manhood, shy Hiccup Horrendous Haddock III faces a rite of passage: he must kill a dragon to prove his warrior mettle. But after downing a feared dragon, he realizes that he no longer wants to destroy it, and instead befriends the beast – which he names Toothless – much to the chagrin of his warrior father', '8.1', '882954', 'https://m.media-amazon.com/images/M/MV5BMjA5NDQyMjc2NF5BMl5BanBnXkFtZTcwMjg5ODcyMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (124, 'Terminator 2: Judgment Day', '1991', 137, 'James Cameron', 'R', 'Nearly 10 years have passed since Sarah Connor was targeted for termination by a cyborg from the future. Now her son, John, the future leader of the resistance, is the target for a newer, more deadly terminator. Once again, the resistance has managed to send a protector back to attempt to save John and his mother Sarah.', '8.6', '1272242', 'https://m.media-amazon.com/images/M/MV5BNGMyMGNkMDUtMjc2Ni00NWFlLTgyODEtZTY2MzBiZTg0OWZiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (125, 'The Amazing Spider-Man 2', '2014', 142, 'Marc Webb', 'PG-13', 'For Peter Parker, life is busy. Between taking out the bad guys as Spider-Man and spending time with the person he loves, Gwen Stacy, high school graduation cannot come quickly enough. Peter has not forgotten about the promise he made to Gwen’s father to protect her by staying away, but that is a promise he cannot keep. Things will change for Peter when a new villain, Electro, emerges, an old friend, Harry Osborn, returns, and Peter uncovers new clues about his past.', '6.6', '582337', 'https://m.media-amazon.com/images/M/MV5BOTA5NDYxNTg0OV5BMl5BanBnXkFtZTgwODE5NzU1MTE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (126, 'Furious 7', '2015', 137, 'James Wan', 'PG-13', 'Deckard Shaw seeks revenge against Dominic Toretto and his family for his comatose brother.', '7.1', '437204', 'https://m.media-amazon.com/images/M/MV5BMTQxOTA2NDUzOV5BMl5BanBnXkFtZTgwNzY2MTMxMzE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (127, 'The Terminator', '1984', 107, 'James Cameron', 'R', 'In the post-apocalyptic future, reigning tyrannical supercomputers teleport a cyborg assassin known as the "Terminator" back to 1984 to kill Sarah Connor, whose unborn son is destined to lead insurgents against 21st century mechanical hegemony. Meanwhile, the human-resistance movement dispatches a lone warrior to safeguard Sarah. Can he stop the virtually indestructible killing machine?', '8.1', '996325', 'https://m.media-amazon.com/images/M/MV5BZmE0YzIxM2QtMGNlMi00MjRmLWE3MWMtOWQzMGVjMmU0YTFmXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (128, 'Star Wars: Episode III - Revenge of the Sith', '2005', 140, 'George Lucas', 'PG-13', 'Years after the onset of the Clone Wars, the noble Jedi Knights lead a massive clone army into a galaxy-wide battle against the Separatists. When the sinister Sith unveil a thousand-year-old plot to rule the galaxy, the Republic crumbles and from its ashes rises the evil Galactic Empire. Jedi hero Anakin Skywalker is seduced by the dark side of the Force to become the Emperor''s new apprentice – Darth Vader. The Jedi are decimated, as Obi-Wan Kenobi and Jedi Master Yoda are forced into hiding. Th', '7.7', '912634', 'https://m.media-amazon.com/images/M/MV5BNTc4MTc3NTQ5OF5BMl5BanBnXkFtZTcwOTg0NjI4NA@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (129, 'Her', '2013', 126, 'Spike Jonze', 'R', 'In the not so distant future, Theodore, a lonely writer purchases a newly developed operating system designed to meet the user''s every needs. To Theordore''s surprise, a romantic relationship develops between him and his operating system. This unconventional love story blends science fiction and romance in a sweet tale that explores the nature of love and the ways that technology isolates and connects us all.', '8.0', '722410', 'https://m.media-amazon.com/images/M/MV5BMjA1Nzk0OTM2OF5BMl5BanBnXkFtZTgwNjU2NjEwMDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (130, 'X-Men', '2000', 104, 'Bryan Singer', 'PG-13', 'Two mutants, Rogue and Wolverine, come to a private academy for their kind whose resident superhero team, the X-Men, must oppose a terrorist organization with similar powers.', '7.3', '688134', 'https://m.media-amazon.com/images/M/MV5BNzNjZjQwOTAtNWQ3NC00MmJlLThlZDEtZmUyMWQ3NmE4Y2Y5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (131, '21 Jump Street', '2012', 109, 'Phil Lord, Christopher Miller', 'R', 'In high school, Schmidt was a dork and Jenko was the popular jock. After graduation, both of them joined the police force and ended up as partners riding bicycles in the city park. Since they are young and look like high school students, they are assigned to an undercover unit to infiltrate a drug ring that is supplying high school students synthetic drugs.', '7.2', '641161', 'https://m.media-amazon.com/images/M/MV5BMTg2NjJiODctM2IyMS00MmQ5LWI1YmQtNTBjMTI4M2U2YzA5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (132, 'Shrek', '2001', 90, 'Andrew Adamson, Vicky Jenson', 'PG', 'It ain''t easy bein'' green -- especially if you''re a likable (albeit smelly) ogre named Shrek. On a mission to retrieve a gorgeous princess from the clutches of a fire-breathing dragon, Shrek teams up with an unlikely compatriot -- a wisecracking donkey.', '7.9', '803764', 'https://m.media-amazon.com/images/M/MV5BN2FkMTRkNTUtYTI0NC00ZjI4LWI5MzUtMDFmOGY0NmU2OGY1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (133, 'The Green Mile', '1999', 189, 'Frank Darabont', 'R', 'A supernatural tale set on death row in a Southern prison, where gentle giant John Coffey possesses the mysterious power to heal people''s ailments. When the cellblock''s head guard, Paul Edgecomb, recognizes Coffey''s miraculous gift, he tries desperately to help stave off the condemned man''s execution.', '8.6', '1543237', 'https://m.media-amazon.com/images/M/MV5BMTUxMzQyNjA5MF5BMl5BanBnXkFtZTYwOTU2NTY3._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (134, 'Transformers', '2007', 144, 'Michael Bay', 'PG-13', 'Young teenager, Sam Witwicky becomes involved in the ancient struggle between two extraterrestrial factions of transforming robots – the heroic Autobots and the evil Decepticons. Sam holds the clue to unimaginable power and the Decepticons will stop at nothing to retrieve it.', '7.1', '709851', 'https://m.media-amazon.com/images/M/MV5BZjM3ZDA2YmItMzhiMi00ZGI3LTg3ZGQtOTk3Nzk0MDY0ZDZhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (135, 'Memento', '2000', 113, 'Christopher Nolan', 'R', 'Suffering short-term memory loss after a head injury, Leonard Shelby embarks on a grim quest to find the lowlife who murdered his wife in this gritty, complex thriller that packs more knots than a hangman''s noose. To carry out his plan, Shelby snaps Polaroids of people and places, jotting down contextual notes on the backs of photos to aid in his search and jog his memory. He even tattoos his own body in a desperate bid to remember.', '8.4', '1424930', 'https://m.media-amazon.com/images/M/MV5BMGQ3Y2Q4NjktN2E4Ny00Y2Q2LTliZDUtZTNiNjRhY2I0NGIyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (136, 'The Hunger Games: Mockingjay - Part 2', '2015', 137, 'Francis Lawrence', 'PG-13', 'With the nation of Panem in a full scale war, Katniss confronts President Snow in the final showdown. Teamed with a group of her closest friends – including Gale, Finnick, and Peeta – Katniss goes off on a mission with the unit from District 13 as they risk their lives to stage an assassination attempt on President Snow who has become increasingly obsessed with destroying her. The mortal traps, enemies, and moral choices that await Katniss will challenge her more than any arena she faced in The ', '6.6', '402657', 'https://m.media-amazon.com/images/M/MV5BNjQzNDI2NTU1Ml5BMl5BanBnXkFtZTgwNTAyMDQ5NjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (137, 'Mission: Impossible - Ghost Protocol', '2011', 132, 'Brad Bird', 'PG-13', 'In the 4th installment of the Mission Impossible series, Ethan Hunt (Cruise) and his team are racing against time to track down a dangerous terrorist named Hendricks (Nyqvist), who has gained access to Russian nuclear launch codes and is planning a strike on the United States. An attempt to stop him ends in an explosion causing severe destruction to the Kremlin and the IMF to be implicated in the bombing, forcing the President to disavow them. No longer being aided by the government, Ethan and h', '7.4', '562053', 'https://m.media-amazon.com/images/M/MV5BMTY4MTUxMjQ5OV5BMl5BanBnXkFtZTcwNTUyMzg5Ng@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (138, 'Die Hard', '1988', 132, 'John McTiernan', 'R', 'NYPD cop, John McClane''s plan to reconcile with his estranged wife is thrown for a serious loop when minutes after he arrives at her office, the entire building is overtaken by a group of terrorists. With little help from the LAPD, wisecracking McClane sets out to single-handedly rescue the hostages and bring the bad guys down.', '8.2', '1021784', 'https://m.media-amazon.com/images/M/MV5BMGNlYmM1NmQtYWExMS00NmRjLTg5ZmEtMmYyYzJkMzljYWMxXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (139, 'Kill Bill: Vol. 2', '2004', 137, 'Quentin Tarantino', 'R', 'The Bride unwaveringly continues on her roaring rampage of revenge against the band of assassins who had tried to kill her and her unborn child. She visits each of her former associates one-by-one, checking off the victims on her Death List Five until there''s nothing left to do … but kill Bill.', '8.0', '852073', 'https://m.media-amazon.com/images/M/MV5BY2FiNzhiZTctNzU1Mi00NDkwLWExNDMtZTg0MjYyNzhkNWNkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (140, 'Fury', '2014', 134, 'David Ayer', 'R', 'Last months of World War II in April 1945. As the Allies make their final push in the European Theater, a battle-hardened U.S. Army sergeant in the 2nd Armored Division named Wardaddy commands a Sherman tank called "Fury" and its five-man crew on a deadly mission behind enemy lines. Outnumbered and outgunned, Wardaddy and his men face overwhelming odds in their heroic attempts to strike at the heart of Nazi Germany.', '7.6', '601009', 'https://m.media-amazon.com/images/M/MV5BMjA4MDU0NTUyN15BMl5BanBnXkFtZTgwMzQxMzY4MjE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (141, 'Sherlock Holmes: A Game of Shadows', '2011', 129, 'Guy Ritchie', 'PG-13', 'There is a new criminal mastermind at large (Professor Moriarty) and not only is he Holmes’ intellectual equal, but his capacity for evil and lack of conscience may give him an advantage over the  detective.', '7.4', '498829', 'https://m.media-amazon.com/images/M/MV5BMTQwMzQ5Njk1MF5BMl5BanBnXkFtZTcwNjIxNzIxNw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (142, 'The Fifth Element', '1997', 126, 'Luc Besson', 'PG-13', 'In 2257, a taxi driver is unintentionally given the task of saving a young girl who is part of the key that will ensure the survival of humanity.', '7.6', '539521', 'https://m.media-amazon.com/images/M/MV5BODU4ZTE5MWYtNmY2MC00NDkyLTk0NDgtNTk5YjgzMzc4NmQwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (143, 'Cars', '2006', 116, 'John Lasseter, Joe Ranft', 'G', 'Lightning McQueen, a hotshot rookie race car driven to succeed, discovers that life is about the journey, not the finish line, when he finds himself unexpectedly detoured in the sleepy Route 66 town of Radiator Springs. On route across the country to the big Piston Cup Championship in California to compete against two seasoned pros, McQueen gets to know the town''s offbeat characters.', '7.3', '522371', 'https://m.media-amazon.com/images/M/MV5BMTg5NzY0MzA2MV5BMl5BanBnXkFtZTYwNDc3NTc2._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (144, 'Ice Age', '2002', 81, 'Chris Wedge, Carlos Saldanha', 'PG', 'With the impending ice age almost upon them, a mismatched trio of prehistoric critters – Manny the woolly mammoth, Diego the saber-toothed tiger and Sid the giant sloth – find an orphaned infant and decide to return it to its human parents. Along the way, the unlikely allies become friends but, when enemies attack, their quest takes on far nobler aims.', '7.5', '560233', 'https://m.media-amazon.com/images/M/MV5BMDBlYzU2OGMtOGJjNi00ZGZjLWIwNjMtYzdiZjkwYWNjZDljXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (145, 'Casino Royale', '2006', 144, 'Martin Campbell', 'PG-13', 'Le Chiffre, a banker to the world''s terrorists, is scheduled to participate in a high-stakes poker game in Montenegro, where he intends to use his winnings to establish his financial grip on the terrorist market. M sends Bond – on his maiden mission as a 00 Agent – to attend this game and prevent Le Chiffre from winning. With the help of Vesper Lynd and Felix Leiter, Bond enters the most important poker game in his already dangerous career.', '8.0', '733930', 'https://m.media-amazon.com/images/M/MV5BMWQ1ZDM4NDktMWY0NC00MjcxLWJlMDMtNmE2MGVhYzRjMWQ0XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (146, 'Raiders of the Lost Ark', '1981', 115, 'Steven Spielberg', 'PG', 'When Dr. Indiana Jones – the tweed-suited professor who just happens to be a celebrated archaeologist – is hired by the government to locate the legendary Ark of the Covenant, he finds himself up against the entire Nazi regime.', '8.4', '1102713', 'https://m.media-amazon.com/images/M/MV5BOGNhMjg2ZjgtYzk4Ni00MTViLTg1MmUtYzM2MDZiYjZlMmU3XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (147, 'Spirited Away', '2001', 124, 'Hayao Miyazaki', 'PG', 'A ten year old girl who wanders away from her parents along a path that leads to a world ruled by strange and unusual monster-like animals. Her parents have been changed into pigs along with others inside a bathhouse full of these creatures. Will she ever see the world how it once was?', '8.6', '954145', 'https://m.media-amazon.com/images/M/MV5BNTEyNmEwOWUtYzkyOC00ZTQ4LTllZmUtMjk0Y2YwOGUzYjRiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (148, 'Back to the Future Part II', '1989', 108, 'Robert Zemeckis', 'PG', 'Marty and Doc are at it again in this wacky sequel to the 1985 blockbuster as the time-traveling duo head to 2015 to nip some McFly family woes in the bud. But things go awry thanks to bully Biff Tannen and a pesky sports almanac. In a last-ditch attempt to set things straight, Marty finds himself bound for 1955 and face to face with his teenage parents -- again.', '7.8', '607494', 'https://m.media-amazon.com/images/M/MV5BMTNlOTRmOTEtMTAyMi00NjFiLTk3NDMtNWI0YzA3ZTZlYjZiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (149, 'Toy Story 2', '1999', 92, 'John Lasseter, Ash Brannon, Lee Unkrich', 'G', 'Andy heads off to Cowboy Camp, leaving his toys to their own devices. Things shift into high gear when an obsessive toy collector named Al McWhiggen, owner of Al''s Toy Barn kidnaps Woody. Andy''s toys mount a daring rescue mission, Buzz Lightyear meets his match and Woody has to decide where he and his heart truly belong.', '7.9', '663076', 'https://m.media-amazon.com/images/M/MV5BNzVmODlhMDEtY2YxZi00OTVjLTlkNTktN2Q2OTRlM2I4M2FhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (150, 'Catch Me If You Can', '2002', 141, 'Steven Spielberg', 'PG-13', 'A true story about Frank Abagnale Jr. who, before his 19th birthday, successfully conned millions of dollars worth of checks as a Pan Am pilot, doctor, and legal prosecutor. An FBI agent makes it his mission to put him behind bars. But Frank not only eludes capture, he revels in the pursuit.', '8.1', '1221144', 'https://m.media-amazon.com/images/M/MV5BMTY5MzYzNjc5NV5BMl5BanBnXkFtZTYwNTUyNTc2._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (151, 'I, Robot', '2004', 115, 'Alex Proyas', 'PG-13', 'In 2035, where robots are common-place and abide by the three laws of robotics, a techno-phobic cop investigates an apparent suicide. Suspecting that a robot may be responsible for the death, his investigation leads him to believe that humanity may be in danger.', '7.1', '604115', 'https://m.media-amazon.com/images/M/MV5BZDdhNTY3YTgtYmQwMC00MjM1LTgzYzMtMGM1N2E0NWM1NDlkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (152, 'Ocean''s Eleven', '2001', 116, 'Steven Soderbergh', 'PG-13', 'Less than 24 hours into his parole, charismatic thief Danny Ocean is already rolling out his next plan: In one night, Danny''s hand-picked crew of specialists will attempt to steal more than $150 million from three Las Vegas casinos. But to score the cash, Danny risks his chances of reconciling with ex-wife, Tess.', '7.7', '668514', 'https://m.media-amazon.com/images/M/MV5BMmNhZDkxYTgtMDM3ZC00NTQ3LWFjZTUtNzc1Y2QyNWZjNDRmXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (153, 'The Great Gatsby', '2013', 143, 'Baz Luhrmann', 'PG-13', 'An adaptation of F. Scott Fitzgerald''s Long Island-set novel, where Midwesterner Nick Carraway is lured into the lavish world of his neighbor, Jay Gatsby. Soon enough, however, Carraway will see through the cracks of Gatsby''s nouveau riche existence, where obsession, madness, and tragedy await.', '7.2', '635505', 'https://m.media-amazon.com/images/M/MV5BMTkxNTk1ODcxNl5BMl5BanBnXkFtZTcwMDI1OTMzOQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (154, 'The Fault in Our Stars', '2014', 126, 'Josh Boone', 'PG-13', 'Despite the tumor-shrinking medical miracle that has bought her a few years, Hazel has never been anything but terminal, her final chapter inscribed upon diagnosis. But when a patient named Augustus Waters suddenly appears at Cancer Kid Support Group, Hazel''s story is about to be completely rewritten.', '7.6', '421191', 'https://m.media-amazon.com/images/M/MV5BYTA4ODg5YWUtYmZiYy00Y2M4LWE0NjEtODE5MzhkYmJmZGEwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (155, 'The Shining', '1980', 146, 'Stanley Kubrick', 'R', 'Jack Torrance accepts a caretaker job at the Overlook Hotel, where he, along with his wife Wendy and their son Danny, must live isolated from the rest of the world for the winter. But they aren''t prepared for the madness that lurks within.', '8.4', '1209484', 'https://m.media-amazon.com/images/M/MV5BNmM5ZThhY2ItOGRjOS00NzZiLWEwYTItNDgyMjFkOTgxMmRiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (156, 'Drive', '2011', 100, 'Nicolas Winding Refn', 'R', 'A Hollywood stunt performer who moonlights as a wheelman for criminals discovers that a contract has been put on him after a heist gone wrong.', '7.8', '754976', 'https://m.media-amazon.com/images/M/MV5BYTFmNTFlOTAtNzEyNi00MWU2LTg3MGEtYjA2NWY3MDliNjlkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (157, 'Reservoir Dogs', '1992', 99, 'Quentin Tarantino', 'R', 'A botched robbery indicates a police informant, and the pressure mounts in the aftermath at a warehouse. Crime begets violence as the survivors -- veteran Mr. White, newcomer Mr. Orange, psychopathic parolee Mr. Blonde, bickering weasel Mr. Pink and Nice Guy Eddie -- unravel.', '8.3', '1157830', 'https://m.media-amazon.com/images/M/MV5BMmMzYjg4NDctYWY0Mi00OGViLWIzMTMtYWNlZGY5ZDJmYjk3XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (158, '12 Years a Slave', '2013', 134, 'Steve McQueen', 'R', 'In the pre-Civil War United States, Solomon Northup, a free black man from upstate New York, is abducted and sold into slavery. Facing cruelty as well as unexpected kindnesses Solomon struggles not only to stay alive, but to retain his dignity. In the twelfth year of his unforgettable odyssey, Solomon’s chance meeting with a Canadian abolitionist will forever alter his life.', '8.1', '782160', 'https://m.media-amazon.com/images/M/MV5BMjExMTEzODkyN15BMl5BanBnXkFtZTcwNTU4NTc4OQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (159, 'Eternal Sunshine of the Spotless Mind', '2004', 108, 'Michel Gondry', 'R', 'Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.', '8.3', '1166070', 'https://m.media-amazon.com/images/M/MV5BMTY4NzcwODg3Nl5BMl5BanBnXkFtZTcwNTEwOTMyMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (160, 'Charlie and the Chocolate Factory', '2005', 115, 'Tim Burton', 'PG', 'A young boy wins a tour through the most magnificent chocolate factory in the world, led by the world''s most unusual candy maker.', '6.7', '566515', 'https://m.media-amazon.com/images/M/MV5BNjcxMjg1Njg2NF5BMl5BanBnXkFtZTcwMjQ4NzMzMw@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (161, 'Edward Scissorhands', '1990', 105, 'Tim Burton', 'PG-13', 'A small suburban town receives a visit from a castaway unfinished science experiment named Edward.', '7.8', '561073', 'https://m.media-amazon.com/images/M/MV5BODJhODczYjUtYzdkMy00Yjc4LTllNWMtZTQ3MDZlYWZjYWEzXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (162, 'The Bourne Identity', '2002', 119, 'Doug Liman', 'PG-13', 'Wounded to the brink of death and suffering from amnesia, Jason Bourne is rescued at sea by a fisherman. With nothing to go on but a Swiss bank account number, he starts to reconstruct his life, but finds that many people he encounters want him dead. However, Bourne realizes that he has the combat and mental skills of a world-class spy – but who does he work for?', '7.8', '609951', 'https://m.media-amazon.com/images/M/MV5BYTk1ZTcyMWMtMWUxYS00MmEzLTlmODYtOTk1MGRjOTg1ZjlmXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (163, 'Zombieland', '2009', 88, 'Ruben Fleischer', 'R', 'Columbus has made a habit of running from what scares him. Tallahassee doesn''t have fears. If he did, he''d kick their ever-living ass. In a world overrun by zombies, these two are perfectly evolved survivors. But now, they''re about to stare down the most terrifying prospect of all: each other.', '7.5', '663399', 'https://m.media-amazon.com/images/M/MV5BMTU5MDg0NTQ1N15BMl5BanBnXkFtZTcwMjA4Mjg3Mg@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (164, 'Monsters University', '2013', 104, 'Dan Scanlon', 'G', 'A look at the relationship between Mike and Sulley during their days at Monsters University — when they weren''t necessarily the best of friends.', '7.2', '421121', 'https://m.media-amazon.com/images/M/MV5BMTUyODgwMDU3M15BMl5BanBnXkFtZTcwOTM4MjcxOQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (165, 'Blade Runner', '1982', 117, 'Ridley Scott', 'R', 'In the smog-choked dystopian Los Angeles of 2019, blade runner Rick Deckard is called out of retirement to terminate a quartet of replicants who have escaped to Earth seeking their creator for a way to extend their short life spans.', '8.1', '876371', 'https://m.media-amazon.com/images/M/MV5BOWQ4YTBmNTQtMDYxMC00NGFjLTkwOGQtNzdhNmY1Nzc1MzUxXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (166, 'X2', '2003', 134, 'Bryan Singer', 'PG-13', 'Professor Charles Xavier and his team of genetically gifted superheroes face a rising tide of anti-mutant sentiment led by Col. William Stryker. Storm, Wolverine and Jean Grey must join their usual nemeses –  Magneto and Mystique – to unhinge Stryker''s scheme to exterminate all mutants.', '7.4', '606261', 'https://m.media-amazon.com/images/M/MV5BNDk0NjYxMzIzOF5BMl5BanBnXkFtZTYwMTc1MjU3._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (167, 'Donnie Darko', '2001', 113, 'Richard Kelly', 'R', 'After narrowly escaping a bizarre accident, a troubled teenager is plagued by visions of a large bunny rabbit that manipulates him to commit a series of crimes.', '8.0', '894255', 'https://m.media-amazon.com/images/M/MV5BMWE3NTYzZmEtM2U5MS00MDZhLTk2ZTQtZTgzNjg0ZGQ5ZjM0XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (168, 'The Matrix Reloaded', '2003', 138, 'Lana Wachowski, Lilly Wachowski', 'R', 'Six months after the events depicted in The Matrix, Neo has proved to be a good omen for the free humans, as more and more humans are being freed from the matrix and brought to Zion, the one and only stronghold of the Resistance.  Neo himself has discovered his superpowers including super speed, ability to see the codes of the things inside the matrix and a certain degree of pre-cognition. But a nasty piece of news hits the human resistance: 250,000 machine sentinels are digging to Zion and woul', '7.2', '666077', 'https://m.media-amazon.com/images/M/MV5BNjAxYjkxNjktYTU0YS00NjFhLWIyMDEtMzEzMTJjMzRkMzQ1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (169, 'The Fast and the Furious', '2001', 106, 'Rob Cohen', 'PG-13', 'Domenic Toretto is a Los Angeles street racer suspected of masterminding a series of big-rig hijackings. When undercover cop Brian O''Conner infiltrates Toretto''s iconoclastic crew, he falls for Toretto''s sister and must choose a side: the gang or the LAPD.', '6.8', '452738', 'https://m.media-amazon.com/images/M/MV5BZGRiMDE1NTMtMThmZS00YjE4LWI1ODQtNjRkZGZlOTg2MGE1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (170, 'Argo', '2012', 120, 'Ben Affleck', 'R', 'As the Iranian revolution reaches a boiling point, a CIA ''exfiltration'' specialist concocts a risky plan to free six Americans who have found shelter at the home of the Canadian ambassador.', '7.7', '663140', 'https://m.media-amazon.com/images/M/MV5BM2QyMGUyZTEtMjE4Yi00M2RiLTgwN2QtZDMxZDNiMTFkMTFjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (171, 'In Time', '2011', 109, 'Andrew Niccol', 'PG-13', 'In the not-too-distant future the aging gene has been switched off. To avoid overpopulation, time has become the currency and the way people pay for luxuries and necessities. The rich can live forever, while the rest try to negotiate for their immortality. A poor young man who comes into a fortune of time, though too late to help his mother from dying. He ends up on the run from a corrupt police force known as ''time keepers''.', '6.7', '477844', 'https://m.media-amazon.com/images/M/MV5BMjA3NzI1ODc1MV5BMl5BanBnXkFtZTcwMzI5NjQwNg@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (172, 'Aladdin', '1992', 90, 'Ron Clements, John Musker', 'G', 'Princess Jasmine grows tired of being forced to remain in the palace and she sneaks out into the marketplace  in disguise where she meets street-urchin Aladdin and the two fall in love, although she may only marry a prince. After being thrown in jail, Aladdin and becomes embroiled in a plot to find a mysterious lamp with which the evil Jafar hopes to rule the land.', '8.0', '497512', 'https://m.media-amazon.com/images/M/MV5BMmQwYWZjZGItYzc0OC00ZDllLTg3NjItOWIyOWYwMDljMjAyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (173, 'Nightcrawler', '2014', 117, 'Dan Gilroy', 'R', 'When Lou Bloom, desperate for work, muscles into the world of L.A. crime journalism, he blurs the line between observer and participant to become the star of his own story. Aiding him in his effort is Nina, a TV-news veteran.', '7.8', '662221', 'https://m.media-amazon.com/images/M/MV5BYjMwMmI5MWQtOTU4OS00OTAyLTg0OTYtNmQ5YzExZTQ3ZWJhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (174, 'The Social Network', '2010', 120, 'David Fincher', 'PG-13', 'On a fall night in 2003, Harvard undergrad and computer programming genius Mark Zuckerberg sits down at his computer and heatedly begins working on a new idea. In a fury of blogging and programming, what begins in his dorm room as a small site among friends soon becomes a global social network and a revolution in communication. A mere six years and 500 million friends later, Mark Zuckerberg is the youngest billionaire in history... but for this entrepreneur, success leads to both personal and le', '7.8', '812001', 'https://m.media-amazon.com/images/M/MV5BMjlkNTE5ZTUtNGEwNy00MGVhLThmZjMtZjU1NDE5Zjk1NDZkXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (175, 'District 9', '2009', 112, 'Neill Blomkamp', 'R', 'Aliens land in South Africa and, with their ship totally disabled,  have no way home. Years later, after living in a slum and wearing out their welcome the ''Non-Humans'' are being moved to a new tent city overseen by Multi-National United (MNU).', '7.9', '748028', 'https://m.media-amazon.com/images/M/MV5BMTM4OTI1OTM5NF5BMl5BanBnXkFtZTcwMzk5MTU1Mg@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (176, 'The Godfather: Part II', '1974', 202, 'Francis Ford Coppola', 'R', 'In the continuing saga of the Corleone crime family, a young Vito Corleone grows up in Sicily and in 1910s New York. In the 1950s, Michael Corleone attempts to expand the family business into Las Vegas, Hollywood and Cuba.', '9.0', '1478804', 'https://m.media-amazon.com/images/M/MV5BMDIxMzBlZDktZjMxNy00ZGI4LTgxNDEtYWRlNzRjMjJmOGQ1XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (177, 'Braveheart', '1995', 178, 'Mel Gibson', 'R', 'Enraged at the slaughter of Murron, his new bride and childhood love, Scottish warrior William Wallace slays a platoon of the local English lord''s soldiers. This leads the village to revolt and, eventually, the entire country to rise up against English rule.', '8.3', '1150527', 'https://m.media-amazon.com/images/M/MV5BNGMxZDBhNGQtYTZlNi00N2UzLWI4NDEtNmUzNWM2NTdmZDA0XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (178, 'Tangled', '2010', 100, 'Nathan Greno, Byron Howard', 'PG', 'When the kingdom''s most wanted-and most charming-bandit Flynn Rider hides out in a mysterious tower, he''s taken hostage by Rapunzel, a beautiful and feisty tower-bound teen with 70 feet of magical, golden hair. Flynn''s curious captor, who''s looking for her ticket out of the tower where she''s been locked away for years, strikes a deal with the handsome thief and the unlikely duo sets off on an action-packed escapade, complete with a super-cop horse, an over-protective chameleon and a gruff gang o', '7.7', '540207', 'https://m.media-amazon.com/images/M/MV5BMTAxNDYxMjg0MjNeQTJeQWpwZ15BbWU3MDcyNTk2OTM@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (179, '22 Jump Street', '2014', 112, 'Phil Lord, Christopher Miller', 'R', 'After making their way through high school (twice), big changes are in store for officers Schmidt and Jenko when they go deep undercover at a local college. But when Jenko meets a kindred spirit on the football team, and Schmidt infiltrates the bohemian art major scene, they begin to question their partnership. Now they don''t have to just crack the case - they have to figure out if they can have a mature relationship. If these two overgrown adolescents can grow from freshmen into real men, colle', '7.0', '436227', 'https://m.media-amazon.com/images/M/MV5BMTcwNzAxMDU1M15BMl5BanBnXkFtZTgwNDE2NTU1MTE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (180, 'American Beauty', '1999', 122, 'Sam Mendes', 'R', 'Lester Burnham, a depressed suburban father in a mid-life crisis, decides to turn his hectic life around after developing an infatuation with his daughter''s attractive friend.', '8.3', '1272515', 'https://m.media-amazon.com/images/M/MV5BMDI1MDE0OTMtMmI2MS00Yjc2LTg2MTItMWExYTg5NzA1OGUzXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (181, 'The Theory of Everything', '2014', 123, 'James Marsh', 'PG-13', 'The Theory of Everything is the extraordinary story of one of the world’s greatest living minds, the renowned astrophysicist Stephen Hawking, who falls deeply in love with fellow Cambridge student Jane Wilde.', '7.7', '505970', 'https://m.media-amazon.com/images/M/MV5BMTAwMTU4MDA3NDNeQTJeQWpwZ15BbWU4MDk4NTMxNTIx._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (182, 'Amélie', '2001', 122, 'Jean-Pierre Jeunet', 'R', 'At a tiny Parisian café, the adorable yet painfully shy Amélie (Audrey Tautou) accidentally discovers a gift for helping others. Soon Amelie is spending her days as a matchmaker, guardian angel, and all-around do-gooder. But when she bumps into a handsome stranger, will she find the courage to become the star of her very own love story?', '8.3', '834716', 'https://m.media-amazon.com/images/M/MV5BOTNmYzY0MWQtZGZmNy00Y2Y4LWFmMDQtMTZjYTdiYzEwZGQ2XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (183, 'The Curious Case of Benjamin Button', '2008', 166, 'David Fincher', 'PG-13', 'Tells the story of Benjamin Button, a man who starts aging backwards with bizarre consequences.', '7.8', '740633', 'https://m.media-amazon.com/images/M/MV5BYjIyNDExOWItM2Y4ZC00NmY3LWFlN2ItYTJlZDQ1NTJlZTUwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (184, 'E.T. the Extra-Terrestrial', '1982', 115, 'Steven Spielberg', 'PG', 'After a gentle alien becomes stranded on Earth, the being is discovered and befriended by a young boy named Elliott. Bringing the extraterrestrial into his suburban California house, Elliott introduces E.T., as the alien is dubbed, to his brother and his little sister, Gertie, and the children decide to keep its existence a secret. Soon, however, E.T. falls ill, resulting in government intervention and a dire situation for both Elliott and the alien.', '7.9', '467067', 'https://m.media-amazon.com/images/M/MV5BYTNhNmY0YWMtMTczYi00MTA0LThhMmUtMTIxYzE0Y2QwMzRlXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (185, 'Independence Day', '1996', 145, 'Roland Emmerich', 'PG-13', 'On July 2, a giant alien mothership enters orbit around Earth and deploys several dozen saucer-shaped ''destroyer'' spacecraft that quickly lay waste to major cities around the planet. On July 3, the United States conducts a coordinated counterattack that fails. On July 4, a plan is devised to gain access to the interior of the alien mothership in space, in order to plant a nuclear missile.', '7.0', '642170', 'https://m.media-amazon.com/images/M/MV5BOGMwN2UwZjEtYjFjMi00ZDA1LWJlYTQtMjA1MTYxMzIyNTdiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (186, 'The Usual Suspects', '1995', 106, 'Bryan Singer', 'R', 'Held in an L.A. interrogation room, Verbal Kint attempts to convince the feds that a mythic crime lord, Keyser Soze, not only exists, but was also responsible for drawing him and his four partners into a multi-million dollar heist that ended with an explosion in San Pedro harbor – leaving few survivors. Verbal lures his interrogators with an incredible story of the crime lord''s almost supernatural prowess.', '8.5', '1229658', 'https://m.media-amazon.com/images/M/MV5BOTE5MDUxZDUtZWZmZC00NDVmLWFhOGQtNWI2YTc4NzY3MGQ0XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (187, 'Madagascar', '2005', 86, 'Eric Darnell, Tom McGrath', 'PG', 'Zoo animals leave the comforts of man-made habitats for exotic adventure in this animated family film. After escaping from the zoo, four friends -- a lion, a hippo, a zebra and a giraffe -- are sent back to Africa. When their ship capsizes, stranding them on Madagascar, an island populated by crazy critters, the pals must adapt to jungle life and their new roles as wild animals.', '6.9', '473809', 'https://m.media-amazon.com/images/M/MV5BYjk4OGFmZmYtYWE4NC00MzM4LTkwZTItODdhMjk3NTZjMmI5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (188, 'Now You See Me 2', '2016', 129, 'Jon M. Chu', 'PG-13', 'One year after outwitting the FBI and winning the public’s adulation with their mind-bending spectacles, the Four Horsemen resurface only to find themselves face to face with a new enemy who enlists them to pull off their most dangerous heist yet.', '6.4', '357612', 'https://m.media-amazon.com/images/M/MV5BOTVjNTA0ZWEtNzU2Ny00Njg1LWE1MmEtZTUyZGQzYTVlY2Q5XkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (189, 'Mission: Impossible - Rogue Nation', '2015', 131, 'Christopher McQuarrie', 'PG-13', 'Ethan and team take on their most impossible mission yet, eradicating the Syndicate - an International rogue organization as highly skilled as they are, committed to destroying the IMF.', '7.4', '443421', 'https://m.media-amazon.com/images/M/MV5BZjUwZjg2ZjAtY2RhZi00YmZjLTlhNGQtOWQwNDk1MjhhM2NhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (190, 'Aliens', '1986', 137, 'James Cameron', 'R', 'When Ripley''s lifepod is found by a salvage crew over 50 years later, she finds that terra-formers are on the very planet they found the alien species. When the company sends a family of colonists out to investigate her story, all contact is lost with the planet and colonists. They enlist Ripley and the colonial marines to return and search for answers.', '8.4', '835609', 'https://m.media-amazon.com/images/M/MV5BZjIyNGJhYzYtN2I1My00OTVhLWEyMzItZTVjNDMzOTVkYWViXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (191, 'Cast Away', '2000', 143, 'Robert Zemeckis', 'PG-13', 'Chuck, a top international manager for FedEx, and Kelly, a Ph.D. student, are in love and heading towards marriage. Then Chuck''s plane to Malaysia ditches at sea during a terrible storm. He''s the only survivor, and he washes up on a tiny island with nothing but some flotsam and jetsam from the aircraft''s cargo.', '7.8', '676631', 'https://m.media-amazon.com/images/M/MV5BOGNjNDI5ZGQtZjRjMy00NzQyLWFiYzQtYjcwNjM3ZDYwNThhXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (192, 'Indiana Jones and the Last Crusade', '1989', 127, 'Steven Spielberg', 'PG-13', 'When Dr. Henry Jones Sr. suddenly goes missing while pursuing the Holy Grail, eminent archaeologist Indiana must team up with Marcus Brody, Sallah and Elsa Schneider to follow in his father''s footsteps and stop the Nazis from recovering the power of eternal life.', '8.2', '858909', 'https://m.media-amazon.com/images/M/MV5BNGIxNzQ0YzYtMjNmYi00YjBlLWFjNzEtNGE3ZGFmYTczM2MwXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (193, 'The Sixth Sense', '1999', 107, 'M. Night Shyamalan', 'PG-13', 'A psychological thriller about an eight year old boy named Cole Sear who believes he can see into the world of the dead. A child psychologist named Malcolm Crowe comes to Cole to help him deal with his problem, learning that he really can see ghosts of dead people.', '8.2', '1128506', 'https://m.media-amazon.com/images/M/MV5BZWQ2OTY0M2UtMTQxNC00MmIzLTllNDQtNDQ0MTQyYzI2M2ZiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (194, 'Kung Fu Panda', '2008', 92, 'Mark Osborne, John Stevenson', 'PG', 'When the Valley of Peace is threatened, lazy Po the panda discovers his destiny as the "chosen one" and trains to become a kung fu hero, but transforming the unsleek slacker into a brave warrior won''t be easy. It''s up to Master Shifu and the Furious Five -- Tigress, Crane, Mantis, Viper and Monkey -- to give it a try.', '7.6', '571657', 'https://m.media-amazon.com/images/M/MV5BZDU5MDNiMGItYjVmZi00NDUxLTg2OTktNGE0NzNlNzM4NzgyXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (195, 'The Secret Life of Walter Mitty', '2013', 114, 'Ben Stiller', 'PG', 'A timid magazine photo manager who lives life vicariously through daydreams embarks on a true-life adventure when a negative goes missing.', '7.3', '365611', 'https://m.media-amazon.com/images/M/MV5BODYwNDYxNDk1Nl5BMl5BanBnXkFtZTgwOTAwMTk2MDE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (196, 'GoodFellas', '1990', 145, 'Martin Scorsese', 'R', 'The true story of Henry Hill, a half-Irish, half-Sicilian Brooklyn kid who is adopted by neighbourhood gangsters at an early age and climbs the ranks of a Mafia family under the guidance of Jimmy Conway.', '8.7', '1378825', 'https://m.media-amazon.com/images/M/MV5BN2E5NzI2ZGMtY2VjNi00YTRjLWI1MDUtZGY5OWU1MWJjZjRjXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (197, 'How to Train Your Dragon 2', '2014', 102, 'Dean DeBlois', 'PG', 'The thrilling second chapter of the epic How To Train Your Dragon trilogy brings back the fantastical world of Hiccup and Toothless five years later. While Astrid, Snotlout and the rest of the gang are challenging each other to dragon races (the island''s new favorite contact sport), the now inseparable pair journey through the skies, charting unmapped territories and exploring new worlds. When one of their adventures leads to the discovery of a secret ice cave that is home to hundreds of new wil', '7.8', '398152', 'https://m.media-amazon.com/images/M/MV5BMzMwMTAwODczN15BMl5BanBnXkFtZTgwMDk2NDA4MTE@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (198, 'The Conjuring', '2013', 112, 'James Wan', 'R', 'Paranormal investigators Ed and Lorraine Warren work to help a family terrorized by a dark presence in their farmhouse. Forced to confront a powerful entity, the Warrens find themselves caught in the most terrifying case of their lives.', '7.5', '605611', 'https://m.media-amazon.com/images/M/MV5BMTM3NjA1NDMyMV5BMl5BanBnXkFtZTcwMDQzNDMzOQ@@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (199, 'The Devil Wears Prada', '2006', 109, 'David Frankel', 'PG-13', 'The Devil Wears Prada is about a young journalist who moves to New York to work in the fashion industry. Her boss however is extremely demanding and cruel and won’t let her succeed if she doesn’t fit into the high class elegant look of their magazine when all she really wants to be a good journalist.', '7.0', '524526', 'https://m.media-amazon.com/images/M/MV5BOWM3NTI3YWEtYjJmMy00M2U5LWI1NzEtZWM3ZDY2ZWNjOGRiXkEyXkFqcGc@._V1_SX300.jpg');
INSERT INTO movies (movie_id, title, release_year, runtime, director, rated, description, imdb_rating, imdb_votes, poster_url) VALUES (200, 'Gran Torino', '2008', 116, 'Clint Eastwood', 'R', 'Walt Kowalski is a widower who holds onto his prejudices despite the changes in his Michigan neighborhood and the world around him. Kowalski is a grumpy, tough-minded, unhappy old man who can''t get along with either his kids or his neighbors. He is a Korean War veteran whose prize possession is a 1972 Gran Torino he keeps in mint condition. When his neighbor Thao, a young Hmong teenager under pressure from his gang member cousin, tries to steal his Gran Torino, Kowalski sets out to reform the yo', '8.1', '854482', 'https://m.media-amazon.com/images/M/MV5BMTc5NTk2OTU1Nl5BMl5BanBnXkFtZTcwMDc3NjAwMg@@._V1_SX300.jpg');
